-- Figure: New York (Cha Cha)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'New York',
    (SELECT id FROM dance_type WHERE name = 'Cha Cha'),
    true,
    'LF',
    'RF',
    'RF',
    'LF',
    'Counter Open PP',
    'Open PP',
    '["Advanced Hip Twist","Aida","Alemana","Basic Movement In Place","Closed Basic Movement","Closed Hip Twist","Cross Basic","Cuban Break RF","Curl","Hand To Hand LSP","Hip Twist Spiral","Hockey Stick","New York RSP","Open Hip Twist","Rope Spinning","Shoulder To Shoulder Right Side","Side Step To Right commenced with RF","Spiral","Split Cuban Break RF","Spot or Switch Turn To L (Lady to R)","Three Cha Cha Chas Forward","Time Step RF","Underarm Turn To R"]',
    '["New York RSP","Spot or Switch Turn To L (Lady to R)","Cuban Break RF","Split Cuban Break RF","Closed Basic Movement","Open Basic Movement","Underarm Turn To R","Hand To Hand LSP","Side Step To Left commenced with RF","Side Step To Right commenced with RF","Time Step RF","Fan","Closed Hip Twist","Three Cha Cha Chas Forward"]',
    'Note: Check step switching from forward movement to back. Standard check on &, more difficult to do. Correct execution shows better control. Syncopated check immediately as stepping on 2. Last step 5: can turn extra to end in RSP (or LSP) and continue with 4-9 of Three Cha Cha Chas fwd. When followed by Hand to Hand, the turning is at the end of 4&1&, sharp turn. Syncopated New Yorker, e.g New York LSP (2&3&4&1) syncopated. Lady: Keep tone in arms, fast, keep arm in middle and not moving around. Suck tummy. Eye very focused on one spot (New Yorker), then immediately another spot (your partner), not wandering. Lady keep LF planted, swivel LF but not moving LF anywhere else. 2: 1/4 turn to L, LF fwd, New Yorker, Fast, &: 1/4 turn to R, facing Man, weight on LF, L leg bent 3: RF to side, squeeze R side, R hip high, weight still on LF. LH patty cake. &: weight on LF 4&: repeat New Yorker. 1: weight on to RF, settle on R hip. Weight more forward, suck tummy. 2 hand hold.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

