-- Figure: Open Hip Twist (Cha Cha)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Open Hip Twist',
                    (SELECT id FROM dance_type WHERE name = 'Cha Cha'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'RF',
                    'Open Position',
                    'Fan Position',
                    '["Advanced Hip Twist","Aida","Chase","Closed Hip Twist","Cuban Break RF","Curl","Follow My Leader","Hockey Stick","Open Basic Movement","Open Hip Twist","Spiral","Split Cuban Break LF","Spot or Switch Turn To L (Lady to R)","Three Cha Cha Chas Forward","Time Step RF","Turkish Towel"]',
                    '["Alemana","Hockey Stick","Hip Twist Spiral","Open Basic Movement","Time Step LF","Open Hip Twist","Curl","Cuban Break LF","Split Cuban Break LF","Chase","Turkish Towel","Sweetheart","Follow My Leader","New York LSP","Spot or Switch Turn To R","Underarm Turn To L","Three Cha Cha Chas Forward","Reverse Top"]',
                    'If a Spiral is done, finish with Runaway Chasse. (LF fwd, RF fwd, turn 1/2 to end LF back). See types of chasses in Cha Cha Technique.
If no Spiral: this can also finish in Open Position (with diagonal side chassse or back chassse), Contact Position (with side chassse), or CPP'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

