                    'LF',
                    'Closed Position',
                    'Closed Position',
                    '["Aida","Alemana","Basic Movement In Place","Closed Basic Movement","Cross Basic","Cuban Break RF","Hand To Hand LSP","New York RSP","Reverse Top","Rope Spinning","Shoulder To Shoulder Right Side","Side Step To Left commenced with RF","Split Cuban Break LF","Spot or Switch Turn To L (Lady to R)","There And Back","Three Cha Cha Chas Forward","Time Step RF","Underarm Turn To R"]',
                    '["Closed Basic Movement","Open Basic Movement","Spot or Switch Turn To R (Lady to L)","Underarm Turn to L","Side Step To Left commenced with LF","Side Step To Right commenced with LF","Hand To Hand RSP","There And Back","Time Step LF","Fan","Cuban Break RF","Split Cuban Break RF"]',
                    'Sit and Pose. Style
Pose, Styling
Style'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
