-- Figure: Three Cha Cha Chas (Cha Cha)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Three Cha Cha Chas',
    (SELECT id FROM dance_type WHERE name = 'Cha Cha'),
    true,
    'RF',
    'RF',
    'LF',
    'LF',
    'Closed Position',
    'Closed Position',
    '["Basic Movement In Place","Closed Basic Movement","Open Basic Movement"]',
    '["Closed Basic Movement","Open Basic Movement","Fan","Alemana","Natural Top"]',
    'Multiple variations including Forward, Back, Forward In Right Side Position (RSP), Forward In Left Side Position (LSP). Includes different hand holds (Normal Hold, Low double hand hold, Alternating Pat-A-Cake hold, No hold). Styling options such as Pat-A-Cake hand change, arm extensions, and specific footwork descriptions. Preceding figures include Basic Movement In Place, Closed Basic Movement, Open Basic Movement. Following figures include Closed Basic Movement, Open Basic Movement, Fan, Alemana, Natural Top. The figure is danced in 9 steps with timing 4&1, 2&3, 4&1.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
