-- Figure: Time Step (Cha Cha)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Time Step',
    (SELECT id FROM dance_type WHERE name = 'Cha Cha'),
    true,
    'LF',
    'RF',
    'RF',
    'LF',
    'Closed Position',
    'Open Position',
    '["Advanced Hip Twist","Aida","Alemana","Basic Movement In Place","Chase","Closed Basic Movement","Closed Hip Twist","Cross Basic","Cuban Break RF","Curl","Follow My Leader","Hand To Hand LSP","Hockey Stick","New York RSP","Open Hip Twist","Rope Spinning","Shoulder To Shoulder Right Side","Side Step To Right commenced with RF","Spiral","Split Cuban Break LF","Spot or Switch Turn To L (Lady to R)","There And Back"]',
    '["Closed Basic Movement (6-10)","Open Basic Movement (6-10)","New York RSP","Spot or Switch Turn To L (Lady to R)","Underarm Turn To R","Shoulder To Shoulder Right Side","Side Step To Left commenced with RF","Side Step To Right commenced with RF","Hand To Hand LSP","Time Step RF","Cuban Break RF","Split Cuban Break RF","Basic Movement In Place","Closed Basic Movement","Cuban Break LF","Hand To Hand RSP","New York LSP","Shoulder To Shoulder Left Side","Side Step To Left commenced with LF","Split Cuban Break RF","Spot or Switch Turn To R (Lady to L)","Time Step LF","Underarm Turn to L","Time Step RF - Following Figures","There And Back","Closed Basic Movement","Open Basic Movement","New York LSP","Spot or Switch Turn To R (Lady to L)","Underarm Turn to L","Shoulder To Shoulder Left Side","Side Step To Left commenced with LF","Side Step To Right commenced with LF","Hand To Hand RSP","Time Step LF"]',
    'There is no physical lead, typical connecting figures: Man dances a Spot or Switch Turn, or LF Cuban Break, while Lady dances RF Time Step. Man dances a RF time step while Lady does Spot or Switch Turn, or LF Cuban Break.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

