-- Figure: Criss Cross Bota Fogos (Shadow Bota Fogos) (Samba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Criss Cross Bota Fogos (Shadow Bota Fogos)',
                    (SELECT id FROM dance_type WHERE name = 'Samba'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'RF',
                    'Open Promenade Position',
                    'Open CPP',
                    '["Criss Cross Voltas","Foot Change","Natural Basic Movement","Reverse Basic Movement","Samba Locks","Samba Walk","Side Basic Movement"]',
                    '["Rolling of the Arm","Samba Walk","Corta Jaca","Natural Roll","Criss Cross Voltas","Maypole","Foot Change","Samba Locks"]',
                    'Alternative finishing positions for LF Samba Walk when it follows Criss Cross Bota Fogos:
Promenade position:
Man turn 1/8 L on Stationary Samba Walk and lady 1 1/8 R on Spot Volta to end facing LOD, both turning body a little less to shape the Promenade Position.
Regain normal hold to follow with a RF Samba Walk in PP or a Side Samba Walk.
Right Side Position
Man turn 1/8 L on Stationary Samba Walk and lady 1 1/8 R on Spot Volta to end facing LOD. (Body also face LOD).
Lower joined hands to just above waist level in front of bodies. Lady''s L hand well across her body at waist level, the Man''s R hand behind her back, taking her L hand in his R hand (double hold)
Follow with a RF Samba Walk into Rolling off the Arm.

Keep shoulder quiet. It should not go up and down.

1 a 2: Traveling Bota Fogos Fwd LRL, passing in front of Man under raised arms. End in Open PP | 1/4 to L over 5 & 6
end DC'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Criss Cross Bota Fogos (Shadow Bota Fogos)' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Samba'));
