-- Figure: Reverse Turn (Samba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Reverse Turn',
                    (SELECT id FROM dance_type WHERE name = 'Samba'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Closed Position',
                    '["Back Rocks","Closed Rocks","Maypole","Natural Basic Movement","Open Rocks","Plait","Reverse Basic Movement","Reverse Roll","Reverse Turn","Rolling Off The Arm","Side Basic Movement"]',
                    '["Reverse Basic Movement","Whisk To Left (Reverse Turn undertuned to face wall)","Traveling Bota Fogos Forward (LF)","Bota Fogos To Promenade and Counter Promenade (Reverse Turn undertuned to face wall)","Reverse Turn","Reverse Roll","Traveling Bota Fogos Back (after step 3)","Back Rocks (after step 3)","Plait (after step 3)"]',
                    'May be repeated. Could use some arm shaping.
When following another Reverse Turn, For Man: step 1 is LOD. Turn 1/4 L between 1 and 2 to back wall, then continue as shown above. (Lady: do the normal opposite.)
Timing: "SQQ SQQ" can be used, the differences would be:
No bounce action.
Full weight is taken on to each step
Footwork: step 2: Ball, step 5 BF
Preceding Figures
Back Rocks
Closed Rocks
Maypole
Natural Basic Movement
Open Rocks
Plait
Reverse Basic Movement
Reverse Roll
Reverse Turn
Rolling Off The Arm
Side Basic Movement
Following Figures
Reverse Basic Movement
Whisk To Left (Reverse Turn undertuned to face wall)
Traveling Bota Fogos Forward (LF)
Bota Fogos To Promenade and Counter Promenade (Reverse Turn undertuned to face wall)
Reverse Turn
Reverse Roll
Traveling Bota Fogos Back (after step 3)
Back Rocks (after step 3)
Plait (after step 3)'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

