-- Figure: Rolling ofthe Arm (Samba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Rolling ofthe Arm',
                    (SELECT id FROM dance_type WHERE name = 'Samba'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'RF',
                    'Right Side Position',
                    'Closed Position',
                    '["Criss Cross Bota Fogos (Shadow Bota Fogos)","Criss Cross Voltas","Natural Basic Movement","Reverse Basic Movement","Side Basic Movement"]',
                    '["Samba Walk in PP: LF","Whisk To Left (when finished with Closed Position)","Reverse Turn (when finished with Closed Position)","Foot Change 8: Right Side Position to Right Shadow Position"]',
                    'Closed Position to follow with a Whisk to L
Man: turn 1/4 R over 4-6 to face wall, continue to turn Lady L on step 6, releasing R to L hand hold, keep RH lightly in contact with Lady as she turns within the circle of R arm. Regain normal hold in Closed Position at the end of Lady''s turn.
Lady: continue to turn an extra 1/4 to L on LF on step 6 to end with LF in front of RF in Cuban Cross position.
Closed Position to follow with a Reverse Turn
Man: lead Lady to turn L and to move well fwd on step 4, then continue to turn Lady strongly to L over step 5 and 6, releasing R to L hand hold, keep RH lightly in contact with Lady as she turns within the circle of R arm. Regain normal hold in Closed Position at end of Lady''s turn.
Lady:
Step 4: LF fwd (1/8 L)
Step 5: RF side having turned 3/8 L
Step 6: LF side in front of Man, having turned 1/2 to L, then continue to turn an extra 1/2 to L on LF to end with LF in front of RF in Cuban Cross Position.
Right Shadow Position:
Dance Foot Change 8.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Rolling ofthe Arm' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Samba'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Rolling ofthe Arm' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Samba'));

