-- Figure: Traveling Bota Fogos Back (Samba)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Traveling Bota Fogos Back',
    (SELECT id FROM dance_type WHERE name = 'Samba'),
    true,
    'RF',
    'RF',
    'LF',
    'RF',
    'Closed Position',
    'Promenade Position',
    '["Maypole","Natural Basic Movement","Reverse Basic Movement","Reverse Roll","Reverse Turn","Side Basic Movement"]',
    '["Samba Walk in PP: RF","Samba Walk: Side","Traveling Volta to Left (turning to face partner on step 1)","Bota Fogos To Promenade and Counter Promenade (4-9)","Foot Change 5: Promenade Position to Right Contra Position"]',
    'Bronze Level figure. Detailed description includes bounce action, weight changes, and turning instructions for both leader and follower. The figure involves a series of back steps in CBMP, side steps with 1/4 turns, and ending in promenade position with slight body turn. Comments include technique cues such as "Nail the RF", "Contract and bounce first", and "Apply pressure to IE of LF".'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

