-- Figure: Traveling Bota Fogos Forward (Samba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Traveling Bota Fogos Forward',
                    (SELECT id FROM dance_type WHERE name = 'Samba'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'LF',
                    'Closed Position',
                    'Contra Position',
                    '["Maypole","Natural Basic Movement","Reverse Basic Movement","Reverse Roll","Reverse Turn","Shadow Circular Volta with LF","Shadow Circular Volta with RF","Shadow Traveling Volta commenced with LF","Shadow Traveling Volta commenced with RF","Side Basic Movement"]',
                    '["Shadow Circular Volta with LF","Shadow Circular Volta with RF","Natural Basic Movement (commenced OP - turn 1/8 R over 2 and 3 to face partner)","Contra Bota Fogos (when same foot Bota Fogos ending in Contra Position)","Round About (when same foot Bota Fogos ending in Contra Position)","Shadow Traveling Volta commenced with RF (when LF Traveling Bota Fogos Fwd is dance with same foot)","Shadow Traveling Viola commenced with LF (when RF Traveling Bota Fogos Fwd is dance with same foot)"]',
                    'Focus on bouncing up action, do not focus on "going down" action.
Pay attention to create upper body line:
Do not lean tilt forward, squeeze the side, back hip up, Body has a more backward feeling.)
Taking small steps, that will help to create higher back hip line.
To create the line, it''s not only in the hips, upper body has to do diagonal stretch, project chest fwd.
Lead for changing from Bota Fogos to Voltas is very subtle - lower the hand.
Lady assumes continuing with Bota Fogo, use visual and hand lead and finish to volta, if she senses more turn and man is going to the same direction.
Can be danced on same foot as partner when in R Shadow Position.
Same foot Bota Fogo commenced with LF may be turned 1/8 or 1/4 to L, leading Lady to turn strongly to L towards end of step 1, then releasing hold (Lady turn 5/8 or 3/4 to L). End in R Contra Position taking normal hold.
Similar (opposite) for Bota Fogo commenced with RF.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Traveling Bota Fogos Forward' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Samba'));
