                    (SELECT id FROM dance_type WHERE name = 'Cha Cha'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Fan Position',
                    '["Alemana","Follow My Leader","Natural Top","Rope Spinning"]',
                    '["Alemana","Hockey Stick","Open Basic Movement (Open Basic; Or","1","2 of Open Basic to Three Cha Cha Chas Back; Or 1-5 of Open Basic to Natural Top)","Time Step LF","Open Hip Twist","Cuban Break LF","Split Cuban Break LF","Chase","Turkish Towel","Sweetheart","Follow My Leader","New York LSP","Spot or Switch Turn To R (Lady to L)","Underarm Turn to L","Three Cha Cha Chas Forward (LSP)","Reverse Top (6-10 or 6-15 Reverse Top)"]',
                    'Alternative finishing positions:
Open Position: Man turn 3/8 to L over steps 7-10
Open CPP
Contact Position:
Man turn 1/2 to L over steps 7-10, dancing chasse side and slightly forward.
Lady 3/4 to L over steps 7-10 dancing chasse with LF behind RF (Cuban Cross). Remain normal hold throughout.'
                )
