-- Figure: Aida (Cha Cha)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Aida',
                    (SELECT id FROM dance_type WHERE name = 'Cha Cha'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'LF',
                    'LSP',
                    'LSP',
                    '["Hand To Hand RSP","Reverse Top","Spot or Switch Turn To R (Lady to L)","Three Cha Cha Chas Forward","Underarm Turn to L"]',
                    '["Time Step LF","Closed Basic Movement","Open Basic Movement"]',
                    'Aida Rock and Spot Turn Ending; Aida Switch an Underarm Turn to Right Ending; The chasse can be replaced with rocks as well.
Leader
2: RF back | 1/8 to R
When following Curl or Spiral, Man''s steps are the same.
Increase tone in L arm. Lower L arm, and start rotating. Release R hand hold.
3: LF back to LSP | 1/8 to R
Slightly lower left arm and turn it with body over 2-5
4 & 1: Back Lock in LSP, RLR | No turn
Opening up the arms.
Follower
2: LF back | 1/8 to L
Keep arm at waist level, don''t raise arm high.
When following Curl or Spiral, Man''s steps are the same. Lady does:
2: LF fwd
3: RF fwd in line with LF to end RF back in LSP (turn 1/2 to L)
3: RF back to LSP | 1/8 to L
4 & 1: Back lock in LSP, LRL | No turn'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

