-- Figure: Cha Cha Cha Closed Basic (Cha Cha)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Cha Cha Cha Closed Basic',
    (SELECT id FROM dance_type WHERE name = 'Cha Cha'),
    true,
    'LF',
    'RF',
    'RF',
    'LF',
    'Closed Position',
    'Open CPP',
    '["Aida","Alemena Development","Basic Movement In Place","Closed Basic Movement","Cross Basic","Cuban Break LF","Cuban Break RF","Foot Changes Method 1","Hand To Hand LSP","Hand To Hand RSP","Natural Opening Out Movement","Natural Top","New York LSP","New York RSP","Open Basic Movement","Reverse Top","Rope Spinning","Shoulder To Shoulder Left Side","Shoulder To Shoulder Right Side","Side Step To Left commenced with LF","Side Step To Left commenced with RF","Side Step To Right commenced with LF","Side Step To Right commenced with RF","Spot or Switch Turn To L (Lady to R)","Spot or Switch Turn To R (Lady to L)","There And Back","Three Cha Cha Chas Back","Three Cha Cha Chas Forward","Time Step LF","Time Step RF","Underarm Turn to L","Underarm Turn To R"]',
    '["Time Step RF (after 1-5)","Open Basic Movement (normal; or after step 1-5 of Closed Basic","follow with 6-10 Open Basic)","Closed Basic Movement","New York LSP (after having turned to Open CPP over 8-10)","Spot or Switch Turn To R (Lady to L)","Underarm Turn to L","Shoulder To Shoulder Left Side","Side Step To Left commenced with LF","Side Step To Right commenced with LF","Hand To Hand RSP (with alternative hold)","There And Back","Time Step LF","Fan","Cross Basic","Cuban Break LF","Split Cuban Break LF","Three Cha Cha Chas Back (afer step 1-2)","Underarm Turn To R (after step 1-5)"]',
    'Closed Position is maintained throughout the figure. Closed Basic can end with Man and Lady turning to Open CPP over 8-10. Man Turning 1/8 R and Lady 1/8 L, man release R hand hold. Variations: No Turn or 1/4 Turn. Ending variation could be in Open CPP over 8-10. Opinion 1: lateral movement (minimal rotation). Opinion 2: hip does continuous figure 8 even on chasse for movement. On "1", push off LF. slightly bigger step. Hip settle on "1&".'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

