-- Figure: Chase (Cha Cha)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Chase',
    (SELECT id FROM dance_type WHERE name = 'Cha Cha'),
    true,
    'LF',
    'LF',
    'RF',
    'RF',
    'Open Position',
    'Open Position',
    '["Advanced Hip Twist","Aida","Closed Hip Twist","Cuban Break RF","Curl","Follow My Leader","Hockey Stick","Open Basic Movement","Open Hip Twist","Spiral","Split Cuban Break LF","Spot or Switch Turn To L (Lady to R)","Three Cha Cha Chas Forward","Time Step RF","Turkish Towel"]',
    '["Open Basic Movement (Normal Open Basic","or 1-2 Open Basic into Three Cha Cha Chas Back","or 1-5 of Open Basic into Natural Top)","Time Step LF","Alemena","Open Hip Twist","Curl","Sweetheart","Turkish Towel","Follow My Leader"]',
    'Styling option: L knee bent. Styling option: R knee bent. Turn is commenced at end of previous beat (for sharper action, can finish full turn at end of "3", then do chasse in place, crossing knees, then LF back). Replace weight to RF | 1/8 to R. Turn is commenced at end of previous beat.'
)
