-- Figure: Closed Hip Twist (Advanced) (Cha Cha)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Closed Hip Twist (Advanced)',
                    (SELECT id FROM dance_type WHERE name = 'Cha Cha'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'RF',
                    'Right Side Position',
                    'Fan Position',
                    '["Alemena","Hand To Hand RSP","Natural Top","New York LSP","Rope Spinning","Shoulder To Shoulder Left Side"]',
                    '["Alemena","Hockey Stick","Open Basic Movement","Time Step LF","Open Hip Twist","Curl","Cuban Break LF","Split Cuban Break LF","Chase","Turkish Towel","Sweetheart","Follow My Leader","New York LSP","Spot or Switch Turn To R","Underarm Turn to L","Three Cha Cha Chas Forward","Reverse Top"]',
                    'Other finishing positions:
Open Position
Man turns 1/4 to L over 7-10
Open CPP
Man turn 1/8 L over 7 & 8, leading lady to overturn on 7, both taking 8 diagonally fwd to chasse in Open CPP
Lady turns an additional 1/8 L on 7 using a loosely crossed spiral action
Contact Position
Man 1/2 L over 7-10, dancing the ahsse side and slightly fwd.
Lady 3/4 L over 7-10 dancing the chasse with LF behind RF as Cuban Cross.
Normal hold retained throughout.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

