-- Figure: Cross Basic (Cha Cha)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Cross Basic',
                    (SELECT id FROM dance_type WHERE name = 'Cha Cha'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'RF',
                    'Closed Position',
                    'Closed Position',
                    '["Aida","Alemana","Basic Movement In Place","Closed Basic Movement","Cross Basic","Cuban Break RF","Hand To Hand LSP","New York RSP","Rope Spinning","Shoulder To Shoulder Right Side","Side Step To Right commenced with RF","Split Cuban Break LF","Spot or Switch Turn To L (Lady to R)","Three Cha Cha Chas Forward","Time Step RF","Underarm Turn To R"]',
                    '["Fan (normal; or after steps 1-5 of Cross Basic","follow with steps 6-10 of Fan)","Hockey Stick (Cross Basic ending in Fan position)","Alemana (Cross Basic ending in Fan position)","New York LSP","Closed Basic Movement","Spot or Switch Turn To R (Lady to L)","Hand To Hand RSP","Side Step To Left commenced with LF","Side Step To Right commenced with LF","There And Back","Time Step LF","Cross Basic","Cuban Break LF","Split Cuban Break LF","Underarm Turn To R (after steps 1-5 of Cross Basic)","Spiral (after steps 1-5 of Cross Basic","leady Lady to do Spiral on step 5","then steps 6-10 of Spiral)"]',
                    'The difference from Closed Basic is that the legs will cross in Cross Basic (in Cuban Cross position)
The figure can be danced in either Closed Position or open no hand hold position.
Guapacha timing is often used on this figure.
Guapacha timing requires firm tone with Man.
2: hold, use center body, "center in" ("zip/button in") and feeling like body is more "up", build energy and power in body, almost a little more fwd energy toward and closer to man before stepping back on RF on "a".
a: Man is sending Lady back, Lady RF back, L knee bent, very fast.
Lady''s body movement is not together with Man, Lady settles R hip, while Man is already going back (his back), Lady needs to finish back step
Man and Lady are moving "away" from each other for a moment, Lady does not go fwd with Man in sync, Lady is delayed
3 4&1: move together with Man. L thigh has to push fwd on lock to move fwd.
When not following with another Cross Basic, the last chasse is taken to side.
On the last chasse 8-10, lady may be lead to Fan Position, Open Position or Open CPP, adjusting turn accordingly. Then, any of the normal follows to those positions may be used.
Gold variation:
Man:
Raise L arm and lead lady into Spiral turn to L on 5.
Get back to normal hold on 8.
Lady:
5/8 L on spiral turn, then two fwd steps continuing to turn L to end RF back and slightly to side facing partner.
Continue with the normal 8-10 of Cross Basic.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

