-- Figure: Cuban Breaks (Cha Cha)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Cuban Breaks',
                    (SELECT id FROM dance_type WHERE name = 'Cha Cha'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'RF',
                    'Open Position',
                    'Open Position',
                    '["Advanced Hip Twist","Aida","Alemana","Basic Movement In Place","Closed Basic Movement","Closed Hip Twist","Cross Basic","Cuban Break RF","Curl","Follow My Leader","Hand To Hand LSP","Hip Twist Spiral","Hockey Stick","New York RSP","Open Hip Twist","Rope Spinning","Shoulder To Shoulder Right Side","Spiral","Spot or Switch Turn To L (Lady to R)","Time Step RF","Turkish Towel","Underarm Turn To R"]',
                    '["Fan (into Fan step 6-10)","Time Step RF","Side Step To Right commenced with RF","Side Step To Left commenced with RF","Hand To Hand LSP","Closed Basic Movement (6-10 of Closed Basic)","Cuban Break RF","Cuban Break RF - Preceding Figures","Cuban Break LF - Preceding Figures","Cuban Break LF - Following Figures","Split Cuban Break RF - Preceding Figures","Split Cuban Break LF - Preceding Figures","Split Cuban Break RF - Following Figures","Split Cuban Break LF - Following Figures"]',
                    'On Cuban Breaks, use the hips to counterbalance foot movements, to allow for faster, free movement. Both Man and Lady would be stepping forward on Cuban Breaks, except one is doing RF Cuban Break, the other is doing LF Cuban Break. Hands: don''t wave around, keep it more or less stable, unaffected on the side.
Split Cuban Break (Lady or Man)
Split Cuban Breaks can be danced in place or normal Cuban Break and may be commenced with either foot in any of the positions given for Cuban Breaks.
2 & 3: Dance 1-3 of LF Cuban Break LRL
Small side steps, body spine not moving much, keep under the body
2: opposite shoulder forward
Finish with on 3 with two straight legs, settle hip, shoulder flat before changing direction.
4 & 1: Dance 1-3 of RF Cuban Break RLR
Note:
Footwork: Ball flat on each step.
Variation: Dance from Open PP or Open CPP: turn, changing hands as in new York. Dance more turn if dancing the New York with quick timing and use only one step in place of the chasse.
Split Cuban Break with Guapacha Timing (Lady or Man)
With RF fwd Split Cuban Break:
Beat count "2&3 4&1
2: hold, Guapacha timing part.
&: RF fwd, flat. LF heel up. Very fast.
3: L heel down. R heel up.
4&1: side chasse.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

