-- Figure: Fan (Cha Cha)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Fan',
                    (SELECT id FROM dance_type WHERE name = 'Cha Cha'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Fan Position',
                    '["Aida","Alemana","Basic Movement In Place","Closed Basic Movement","Cross Basic","Cuban Break LF","Cuban Break RF","Hand To Hand LSP","Hand To Hand RSP","Natural Opening Out Movement","Natural Top","New York LSP","New York RSP","Open Basic Movement","Reverse Top","Rope Spinning","Shoulder To Shoulder Left Side","Shoulder To Shoulder Right Side","Side Step To Left commenced with RF","Side Step To Right commenced with LF","Side Step To Right commenced with RF","Split Cuban Break LF","Split Cuban Break RF","Spot or Switch Turn To L (Lady to R)","Spot or Switch Turn To R (Lady to L)","There And Back","Three Cha Cha Chas Back","Three Cha Cha Chas Forward","Time Step RF","Underarm Turn to L","Underarm Turn To R"]',
                    '["Alemana","Hockey Stick"]',
                    'Variations:
Man can take 1/4 L over steps 2-5 and 1/8 over 7-10. (Lady: 1/4 L over 2-5, 3/8 over 7-10)
Gold: Man and Lady: Guapacha timing could be used on 6-10.
Silver & Bronze variation below is what''s often used/seen
Leader (Silver/Gold)
2: LF fwd
3: Transfer weight to RF | 1/4 to L over 2-5
4 & 1: LF to side, slightly back to chasse LRL, ending promenade position
2: RF back
3: Transfer weight to LF | 1/8 to L over 7-10
Increase tone in left arm, release right hand hold
4 & 1: RF to side to chasse RLR end in Fan Position
Slightly extend left arm. Left hand still.
Follower (Silver/Gold)
2: RF back
3: Transfer weight to LF | 1/8 to L over 2-5
4 & 1: Diag fwd lock RLR, end in PP
2: LF fwd, passing in front of Man''s body
3: RF fwd inline with LF, then turn to end RF back | 1/2 to L, body turns less
4 & 1:Back Lock, LRL, end in Fan Position | body completes turn'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

