-- Figure: Follow My Leader (Cha Cha)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Follow My Leader',
                    (SELECT id FROM dance_type WHERE name = 'Cha Cha'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'LF',
                    'Open Position',
                    'Open Position',
                    '["Advanced Hip Twist","Aida","Chase","Closed Hip Twist","Cuban Break RF","Curl","Hockey Stick","Open Basic Movement","Open Hip Twist","Spiral","Split Cuban Break LF","Spot or Switch Turn To L (Lady to R)","Three Cha Cha Chas Forward","Time Step RF","Turkish Towel"]',
                    '["Alemana","Open Basic Movement (Open Basic; Or","1","2 of Open Basic to Three Cha Cha Chas Back; Or 1-5 of Open Basic to Natural Top)","Time Step LF","Open Hip Twist","Curl","Cuban Break LF","Split Cuban Break LF","Chase","Turkish Towel","Advanced Hip Twist","Hip Twist Spiral","Sweetheart"]',
                    'Steps 8 through 25 have a figure 8 pattern.
When turning R, Man takes slightly smaller steps. Lady is following him and her circumference of circle is larger.
When turning L, the roles are reversed, and Lady takes smaller steps.
Alternative finishing position
Man and Lady dance a fwd lock toward partner''s R side on steps 28-30. Man turns body slightly R to invite Lady to his R side. Then, follow with Advanced Hip Twist or Hip Twist Spiral.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
