-- Figure: Hand to Hand (Cha Cha)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Hand to Hand',
    (SELECT id FROM dance_type WHERE name = 'Cha Cha'),
    true,
    'LF',
    'LF',
    'RF',
    'RF',
    'Closed Position',
    'Open Position',
    '["Aida","Alemana","Basic Movement In Place","Closed Basic Movement","Cross Basic","Cuban Break RF","Hand To Hand LSP","New York RSP","Rope Spinning","Shoulder To Shoulder Right Side","Side Step To Right commenced with RF","Split Cuban Break LF","Spot or Switch Turn To L (Lady to R)","There And Back","Three Cha Cha Chas Forward","Time Step RF","Underarm Turn To R"]',
    '["Closed Basic Movement (6-10)","Open Basic Movement (6-10)","New York RSP","Spot or Switch Turn To L (Lady to R)","Underarm Turn To R","Hand To Hand LSP","Side Step To Left commenced with RF","Side Step To Right commenced with RF","Time Step RF","Three Cha Cha Chas Forward (in RSP","after step 2)","Fan (6-10","Lady in line on step 6 of Fan)","Closed Hip Twist (6-10","leading Lady with R hand to turn R","then changing to L to R hand hold on step 7)","Aida","Spiral (Spiral ending: Man almost closes LF to RF on 3 to chasse and leads Lady into her spiral action on 5 to continue with 6-10 of Spiral)","Cuban Break RF","Split Cuban Break RF"]',
    'Start in Closed Position. Like reverse New Yorker. Man take R to L hand hold at end of previous figure, simultaneously releasing L to R hand hold when needed. This figure can start with normal hold. Man allows R hand to slide further around Lady''s back on step 1, releasing hold with L land. Lady slide L hand across Man''s shoulder. For LSP: Man places L hand on Lady''s back, releasing R hand hold at end of step 5, while Lady rests R hand lightly across Man''s L shoulder. Man''s hand on Lady''s back is just below her shoulder blade. Take required hold at end of figure. This may end in Open PP for Hand To Hand RSP, or Open CPP for Hand to Hand LSP.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

