-- Figure: Change ofHands Behind Back (Jive)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Change ofHands Behind Back',
                    (SELECT id FROM dance_type WHERE name = 'Jive'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Open Position',
                    'Open Position',
                    '["American Spin","Catapult","Change of Hands Behind Back","Change of Places Left to Right","Chugging","Fallaway Throwaway","Hip Bump","Rolling Off the Arm","Shoulder Spin","Simple Spin","Spanish Arms","Stop and Go"]',
                    '["Link","Change of Places Left to Right","Change of Hands Behind Back","Hip Bump","American Spin (from L to R hand hold)","Stop and Go"]',
                    'Variation: use of hands:
5: place lady''s RH on R side of waist.
6: release L to R hand hold, allowing lady''s R hand to trail around waist.
catch L to R hand hold at the end of turn.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
