-- Figure: Change of Places Left to Right (Jive)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Change of Places Left to Right',
                    (SELECT id FROM dance_type WHERE name = 'Jive'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'RF',
                    'Open Position',
                    'Open Position',
                    '["American Spin","Change of Hands Behind Back","Change of Places Right to Left","Chugging","Fallaway Throwaway","Hip Bump","Miami Special","Rolling Off the Arm","Shoulder Spin","Simple Spin","Spanish Arms","Stop and Go","Whip Throwaway","Windmill"]',
                    '["Chugging","Toe Heel Swivels","Hip Bump","Link","American Spin","Stop and Go","Windmill","Spanish Arms","Rolling Off the Arm","Simple Spin","Stalking Walks","Flicks and Break","Miami Special","Shoulder Spin","Catapult"]',
                    'Variation - Change of hands: 2 options
Start with R-to-R hand hold. Man leads lady to start turn L on step 3, then release R hand hold. Take L to R hand hold at the end of lady''s turn.
Same as table above or option 1, except that at the end, take R-to-R hand hold.
Development: Overturned Change of Places from Left to Right
On 5:
Many lowers L arm and turns lady strongly L by rotating his hand to R from wrist until palm is turned outwards, giving lady''s R arm a gental twist.
Lady continues to turn an extra 1/2 on RF allowing LF to cross loosely in front of RF (Spiral action) in Tandem position in front of Man.
On 6-8:
Lady may dance a forward lock or 3 small runs fwd.
At end of 8, Man turns lady to R to face him by rotating his hand slightly L from wrist.
Lady turns 1/4 R on LF to end in open position with LF back.
Follow with Chicken Walks, Simple spin from open position or other figures starting in open position. (Lady normally does a flick or oint ball change in place of 1-2 of Link.)'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Change of Places Left to Right' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Jive'));
