-- Figure: Change ofPlaces Right to Left (Jive)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Change ofPlaces Right to Left',
                    (SELECT id FROM dance_type WHERE name = 'Jive'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Open Position',
                    '["Basic In Place","Fallaway Rock","Link","Mooch","Reverse Whip","Stalking Walks","Flicks and Break","Toe Heel Swivels","Walks","Whip"]',
                    '["Chugging","Link","Change of Places Left to Right (normal; or with change of hands when Change of Places R to L is danced with change of hands)","Change of Hands Behind Back","Hip Bump","American Spin (from L to R hand hold; or when Change of Places R to L is danced with change of hands)","Stop and Go","Miami Special (when Change of Places R to L is danced with change of hands)","Shoulder Spin (when Change of Places R to L is danced with change of hands)","Catapult (when Change of Places R to L is danced with change of hands)"]',
                    'Variation - Change of hands: 2 options
lead lady with RH to turn R on 5, release R hand hold. Catch R-to-R hand hold at end of lady''s turn.
Man leads lady do a R underarm turn and change to R-to-R hand hold at end of her turn.
Development:
Man leads the lady to increase her speed on step 5, Man keeping his arm raised until step 8.
Lady spin about 1 1/8 R on RF toward end of 5, then continue to turn another 5/8 to R over 6-8 to end LF back in open position.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
