-- Figure: Advanced Hip Twists (Rumba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Advanced Hip Twists',
                    (SELECT id FROM dance_type WHERE name = 'Rumba'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Fan Position',
                    '["Alemana","Circular Hip Twists","Continuous Hip Twists","Natural Top","Rope Spinning","Three Alemanas","Three Threes"]',
                    '["Alemana","Hockey Stick","Sliding Doors","Fencing","Three Alemanas","Open Hip Twist","Curl","Three Threes","New York LSP","Spot or Switch Turn To R (Lady to L)","Underarm Turn To L","Reverse Top"]',
                    'Alternative finishing positions:
Open Position: Man turn 3/8 to L over steps 5 and 6.
Open CPP
Contact Position: use normal hold.
Man turn 1/2 to L over steps 5 and 6 to end RF to side and slightly fwd.
Lady: 3/4 to L over steps 5 and 6 to end LF behind RF as Cuban Cross.
Man can use "Press Line" on step 1 by making a slight swivel to R on RF and placing LF fwd on ball of foot with pressure but with partial weight.
This can be danced following Alemana with R to R hand hold, changing to L to R hand hold on step 5 of this figure.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

