-- Figure: Aida (4 Endings) (Rumba)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Aida (4 Endings)',
    (SELECT id FROM dance_type WHERE name = 'Rumba'),
    true,
    'RF',
    'RF',
    'LF',
    'LF',
    'Closed Position',
    'Left Side Position (LSP)',
    NULL,
    NULL,
    'Ending with Cuban Rock and Spot Turn; Ending with Double Spot Turn; Ending With Side Cucaracha. Details: Leader transfers weight to LF and performs Cuban Rock in LSP LRL, then RF fwd and slightly across after turning 1/2 to L, Spot Turn or Switch Turn; Follower transfers weight to RF and performs analogous movements. Further endings include Side Cucaracha with described turns.'
)
