-- Figure: Cuban Rocks (Samba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Cuban Rocks',
                    (SELECT id FROM dance_type WHERE name = 'Samba'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'LF',
                    'Open Position',
                    'Open PP',
                    '["Aida","Alemena"]',
                    '["New York","Underarm Turn"]',
                    'This is a Newcomer Level figure. This online reference gives a detailed description of dance steps; a list of figures that may precede or follow the pattern; and videos providing instruction and demonstration of the figure, techniques and practice routines that include it.
See Rumba Technique for details on hip motion.
Cuban Rocks is 3 weight changes while keep feet in place and apart. Can be used when Man or Lady does Spot Turn or Switch Turn.
Normal hold, L to R hand hold, no hold. Try to keep both knees straight for all steps.
May use rotary or lateral hip action.
LF Cuban Rock may end in Open PP (slight turn L on 3, lady 4).
RF Cuban Rock may end in Open CPP (slight turn R on 3, Lady L)
Cuban Rock can be danced in LSP as an ending to Aida.
Some coach prefers: both heels on ground till the last one.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

