-- Figure: Progressive Walks (Rumba)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Progressive Walks',
    (SELECT id FROM dance_type WHERE name = 'Rumba'),
    true,
    'LF',
    'RF',
    'RF',
    'LF',
    'Closed Position',
    'Closed Position',
    '["Basic Movements: Open","Sliding Doors","Spot or Switch Turn to L (Lady to R)"]',
    '["Basic Movements: Open","Basic Movements: Closed","Fan","Alemana","Open Hip Twist","Curl","Three Threes","Three Alemanas","Underarm Turn To R","Hand To Hand LSP","Side Step To Left commenced with RF","Side Step To Right commenced with RF","Cuban Rocks RF","Fan","Closed Hip Twist","Syncopated Cuban Rocks RF"]',
    'Danced in group of 3 or 6 forward or backward steps. Danced in Closed Position or Open Position. No turn or curve to L for walk forward or to R for walk back. See technique details in Latin Technique. When using Shadow holds 2 or 3, the man could lead the lady to dance a spiral turn L when he has danced a Walk Forward on his LF (Lady RF fwd then make a complete turn to L on RF). Continue with Progressive Walks Forward (Man starts RF, Lady LF). Ending: Fan Position: Man leading lady to pass in front of him to his L side, Man turns 1/8 L, Lady 7/8 L. When using Shadow hold 1, change to L to R hand hold on step 5 of Fan. Ending facing partner: omit 6th Forward Walk and both step to side, turning 1/4 to R, Lady to L to face partner. Spiral Ending: Omit 6th Forward Walk and close LF to RF leading Lady into a spiral turn to L. Lady turn 1/4 L on the 6th walk to end in front of Man to dance her spiral turn. Continue with 4-6 Spiral - this is solo spiral for Lady when R Shadow Hold 1 is used.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

