-- Figure: Rope Spinning (Rumba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Rope Spinning',
                    (SELECT id FROM dance_type WHERE name = 'Rumba'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Closed Position',
                    '["Alemena","Continuous Hip Twists","Hand To Hand LSP","Natural Top","Rope Spinning","Three Alemanas"]',
                    '["Hand To Hand RSP (both stepping to side; or When Man and Lady end to side)","Basic Movements: Closed","Basic Movements: Open","Fan","Opening Out To Right And Left (Lady end Rope Spinning LF to side)","Side Step To Left commenced with LF (When Man and Lady end to side)","Side Step To Right commenced with LF (When Man and Lady end to side)","Cuban Rock LF (When Man and Lady end to side)","Syncopated Cuban Rock LF (When Man and Lady end to side)","New York LSP (When ending in Open CPP)","Spot or Switch Turn To R (Lady to L) (When ending in Open CPP)","Underarm Turn To L (When ending in Open CPP)","Natural Opening Out Movement (When Lady ends fwd to Man''s Right side)","Closed Hip Twist (When Lady ends fwd to Man''s Right side)","Spiral (When Lady ends fwd to Man''s Right side)","Rope Spinning (When Lady ends fwd to Man''s Right side)","Advanced Hip Twists (When Man and Lady fwd toward partner''s R side)","Continuous Hip Twists (When Man and Lady fwd toward partner''s R side)","Circular Hip Twists (When Man and Lady fwd toward partner''s R side)","Progressive Walks Forward in Right Shadow Position (When ending in R Shadow Position)","Sliding Doors (When ending in R Shadow Position","follow with 7-12 of Sliding Doors.)"]',
                    'Man and Lady end to side
Man and lady end diagonally fwd in Open CPP
Man 1/8 R on step 6.
Lady 7/8 to R over step 1 to 6.
Lady end fwd toward Man''s R side
Man turns body slightly R on step 6 to lead Lady towards his R side.
Lady LF fwd in line with RF.
Man and Lady fwd towards partner''s R side
Man RF fwd in line with LF towards Lady''s R side.
Lady LF fwd in line with RF
R Shadow Position
Man RF fwd in line with LF towards Lady''s R side, and continues to turn her R.
Lady ends LF back having made 1/2 turn R on LF during preceding beat.
Adopt R shadow Hold.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

