-- Figure: Spiral Turn (Rumba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Spiral Turn',
                    (SELECT id FROM dance_type WHERE name = 'Rumba'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Fan Position',
                    '["Aida","Alemana Development","Hand to Hand (To Right and Left SP)","Natural Top","Opening Out To Right And Left","Progressive Walks Forward in Right Shadow Position","Reverse Top","Rope Spinning","Sliding Doors","Three Alemanas"]',
                    '["Alemana Development","Hockey Stick","Sliding Doors","Fencing","Three Alemanas","Open Hip Twist","Curl","Three Threes","New York LSP","Underarm Turn To L","Reverse Top"]',
                    'Note:
Alternatives:
Underturned Spiral Turn:
Man: turn 1/8 L over step 5 and 6 to end in Open Position with RF fwd.
Lady 3/4 L after she has placed step 3. End in Tandem Position with Man; Lady LF fwd,; RF fwd in line with LF, then turn 1/2 to end with RF back; then LF back.
Ending in Open Position:
Man turn 3/8 to L over step 5 and 6.
End in Open CPP.
End in Contact Position: Closed Spiral
Man turn 5/8 to L over step 5 and 6 to Contact Position, to end RF side and slightly fwd, overturning Lady, keeping fingers lightly in contact with Lady''s waist throughout as she turns within the circle of his R arm. On step 4, lower arms to normal position.
Lady: make a complete turn L over step 4 to 6 to end LF behind RF as Cuban Cross
Preceding Figures
Aida
Alemana
Hand To Hand RSP
Natural Top
Opening Out To Right And Left
Progressive Walks Forward in Right Shadow Position
Reverse Top
Rope Spinning
Sliding Doors
Three Alemanas
Following Figures
Alemana (normal; or When finished in Open Position)
Hockey Stick
Sliding Doors
Fencing
Three Alemanas (normal; or When finished in Open Position)
Basic Movements: Open (When finished in Open Position, follow with Open Basic, or 1-3 Open Basic into Progressive Walks Back or Natural Top)
Open Hip Twist (When finished in Open Position)
Curl (When finished in Open Position)
Three Threes (When finished in Open Position)
New York LSP (When finished in Open CPP)
Spot or Switch Turn To R (Lady to L) (When finished in Open CPP)
Underarm Turn To L (When finished in Open CPP)
Reverse Top (When finished in Contact Position, follow with 4-6 or 4-9 Reverse Top.)'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

