-- Figure: Spot Turns (including Switch Turns, Underarm Turns) (Rumba)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Spot Turns (including Switch Turns, Underarm Turns)',
    (SELECT id FROM dance_type WHERE name = 'Rumba'),
    true,
    'RF',
    'RF',
    'LF',
    'LF',
    'Closed Position',
    'Open Position',
    '["Advanced Hip Twists","Alemana","Basic Movements: Closed","Closed Hip Twist","Cuban Rocks RF","Cucarachas: RF","Curl","Fencing","Hand To Hand LSP","Hockey Stick","New York RSP","Open Hip Twist","Progressive Walks Forward in LSP","Rope Spinning","Shoulder To Shoulder Right Side","Side Step To Right commenced with RF","Spiral","Spot or Switch Turn to L (Lady to R)","Syncopated Cuban Rock LF","Underarm Turn To R"]',
    '["Basic Movements: Open (4-6)","Basic Movements: Closed (4-6)","New York RSP","Spot or Switch Turn to L (Lady to R)","Underarm Turn To R","Hand To Hand LSP","Side Step To Left commenced with RF","Side Step To Right commenced with RF","Cuban Rocks RF","Fan (4-6)","Aida","Syncopated Cuban Rocks RF","Rumba Underarm Turn to Right"]',
    'Spot Turn or Switch Turn to L (Lady to R) could end in Open Position, taking L to R hand hold at step 3, taking step 3 fwd leading Lady to step back. Spot Turn is a common ending for New York, Hand to Hand, Fencing and many other figures. Amount of Turns: complete turn, or 7/8 or 3/4, depending on starting and ending position: open PP, Open CPP, facing partner.'
)
