-- Figure: Three Alemanas (Rumba)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Three Alemanas',
    (SELECT id FROM dance_type WHERE name = 'Rumba'),
    true,
    'LF',
    'RF',
    'RF',
    'LF',
    'Fan Position',
    'Fan Position',
    '["Advanced Hip Twists","Closed Hip Twist","Curl","Fan","Hockey Stick","Open Hip Twist","Opening Out From Reverse Top","Progressive Walks Forward","Spiral","Spot or Switch Turn to L (Lady to R)","Three Threes"]',
    '["Circular Hip Twists","Continuous Hip Twists","Advanced Hip Twists","Sliding Doors","Rope Spinning","Spiral","Closed Hip Twist","Natural Opening Out Movement","Cuban Rock LF","Side Step To Right","Side Step To Left","Hand To Hand RSP","New York LSP","Basic Movements: Closed","Basic Movements: Open","Fan","Opening Out To Right And Left"]',
    'There are a lot of turns/twists. Step onto foot, axis moved to the new standing foot, turn/twist around axis (shoulder first, hip follows), release free hip, move to new axis and start over. One coach''s imagery: rotisserie chicken on a skewer. The axis/skewer does not change, shift, break or move. chicken rotates around skewer.'
)
