-- Figure: Three Threes (Rumba)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Three Threes',
    (SELECT id FROM dance_type WHERE name = 'Rumba'),
    true,
    'LF',
    'LF',
    'RF',
    'RF',
    'Open Position',
    'Closed Position',
    '["Advanced Hip Twists","Basic Movements: Open","Closed Hip Twist","Curl","Hockey Stick","Open Hip Twist","Progressive Walks Forward","Spiral","Spot or Switch Turn to L (Lady to R)"]',
    '["Basic Movements: Closed","Basic Movements: Open","Fan","Advanced Hip Twists","Continuous Hip Twists","Circular Hip Twists","Alemana (when ending in Fan Position)","Hockey Stick (when ending in Fan Position)","Sliding Doors (when ending in Fan Position)","Fencing (when ending in Fan Position)"]',
    'Note: Lady''s alternative steps for steps 10 to 12: dance 1-2 of Switch Turn to R (1/2 turn). Then count 41: LF fwd, after having turned another 1/2 to R. No turn on step 9, then turn 1/4 to R into step 1 and 2 of LF Side Cucaracha on count 2 3; then LF fwd. Then, LF fwd after having turned a further 1/4 to R. Finishing Position: Man and lady can step fwd towards partners R side, followed by different Hip Twists. Fan Ending: Man: Step 9 (41): Close LF to RF, 1/8 to L; Increase tone, L arm slightly fwd. R arm slightly back; then release hold allowing R hand to slide down Lady''s R arm to R to R hand hold. 2: RF back, no turn; R arm towards L side, then change to L to R hand hold. 3: Transfer weight to LF, 1/8 to L, over count 3 4 1; increase tone in L arm. 41: RF to side in Fan Position. Slightly extend L arm. Lady: Step 10-12: dance the finishing steps for Closed Hip Twist to end in Fan Position. 2: LF fwd passing in front of Man''s body. 3: RF fwd in line with LF, then turn 1/2 to L, body turns less; ending RF back. 41: LF back in Fan position, body completes turn.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Three Threes' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Rumba'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Three Threes' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Rumba'));

