-- Figure: Natural Basic Movement (Samba)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Natural Basic Movement',
    (SELECT id FROM dance_type WHERE name = 'Samba'),
    true,
    'RF',
    'RF',
    'LF',
    'LF',
    'Closed Position',
    'Closed Position',
    '["Back Rocks","Closed Rocks","Corta Jaca","Maypole","Natural Basic Movement","Natural Roll","Plait","Progressive Basic Movement","Reverse Basic Movement","Samba Walk: Stationary","Side Basic Movement","Traveling Bota Fogos Forward","Whisk To Left","Whisk To Right"]',
    '["Cruzados Walks and Locks","Samba Locks","Promenade And Counter Promenade Runs","Natural Roll","Round About","Contra Bota Fogos","Shadow Circular Volta with RF","Maypole","Plait","Back Rocks","Open Rocks","Closed Rocks","Corta Jaca","Shadow Traveling Volta with RF","Solo Spot Volta to Right","Criss Cross Voltas","Traveling Bota Fogos Back","Traveling Bota Fogos Forward","Traveling Volta to Left","Rhythm Bounce","Samba Walk Stationary","Samba Walk Side","Samba Walk in PP RF","Whisk To Right","Side Basic Movement","Progressive Basic Movement","Three Step Turn","Reverse Roll","Shadow Circular Volta with LF","Argentine Crosses","Rolling Off The Arm","Reverse Turn","Shadow Traveling Volta with LF","Solo Spot Volta to Left","Bota Fogos To Promenade and Counter Promenade","Criss Cross Bota Fogos","Traveling Volta to Right","Samba Walk in PP LF","Whisk To Left","Reverse Basic Movement","Samba Reverse Basic Movement"]',
    'Use minimal bounce and use 4 steps as below. When used as a Precede to Traveling Bota Fogos Forward, start Natural Basic Movement facing LOD and turn 1/8 L over 2 and 3. 4-6 are then danced with follower outside. When used as a Follow to Traveling Bota Fogos Forward, the first step is outside partner. Turn 1/8 R over 2 and 3 to face partner. Precedes: any figure ending facing partner with weight on LF. Follows: any figure commenced with RF.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

