-- Figure: Hockey Stick (Cha Cha)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Hockey Stick',
                    (SELECT id FROM dance_type WHERE name = 'Cha Cha'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Fan Position',
                    'Open Position',
                    '["Advanced Hip Twist","Closed Hip Twist","Cross Basic","Curl","Fan","Natural Top","Open Hip Twist","Opening Out From Reverse Top","Spiral","Sweetheart"]',
                    '["Open Basic Movement","Shoulder To Shoulder Left Side","Time Step LF","Alemana","Open Hip Twist","Curl","Chase","Turkish Towel","Sweetheart","Follow My Leader","Three Cha Cha Chas Forward","New York LSP","Spot or Switch Turn To R","Underarm Turn to L","Cuban Break LF","Split Cuban Break LF"]',
                    'Other Finishing positions:
Open CPP
Man leads Lady to overturn towards end of 7, both taking 8 diagonally fwd in Open CPP to chasse.
Lady turns an additional 1/4 L on RF using a loosely crossed spiral action.
Left Side Position (LSP)
Man leads Lady to overturn towards end of 7, then turns 1/8 R to chasse fwd, lowering L arm and taking it fwd to below shoulder level.
Lady turns towards end of 7 as for CPP above, then turns an additional 1/8 L, to chasse fwd
Forward Runs could be used in place of last chasse'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

