-- Figure: Miami Special (Jive)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Miami Special',
                    (SELECT id FROM dance_type WHERE name = 'Jive'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'RF',
                    'Open Position',
                    'LSP',
                    '["American Spin","Catapult","Change of Places Left to Right","Change of Places Right to Left","Chugging","Rolling Off the Arm","Shoulder Spin"]',
                    '["Hip Bump (normal; or Man turn 1/8 to R over steps 3-5","Lady 1/8 to L)","Link","Change of Places Left to Right (Man turn 1/4 R over steps 3-6","Lady 1/2 to L)"]',
                    'Raise R hand and circle it strongly counterclockwise over Lady''s head. At end of 5, continue to circle R hand strongly over own head. Place R hand on R shoulder. At same time place L hand on Lady''s L shoulder blade.
Release hold with R hand. Gradually slide L hand along Lady''s R arm to take L to R hand hold on step 8.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
