-- Figure: Rolling Off the Arm (Jive)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Rolling Off the Arm',
                    (SELECT id FROM dance_type WHERE name = 'Jive'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Open Position, Right to Left hand hold',
                    'Open Position, R to L hand hold',
                    '["American Spin","Catapult","Change of Places Left to Right","Chugging","Rolling Off the Arm"]',
                    '["Change of Hands Behind Back","Change of Places Left to Right","Rolling Off the Arm","Windmill","Spanish Arms","American Spin","Miami Special","Shoulder Spin","Chugging","Catapult"]',
                    'Double hand hold:
Turn lady under raised L arm over step 3 and 4, lowering arm to waist level in front of bodies on step 5, releasing L to R hand hold at end of step 7.
Right to Right hand hold - get to this hand hold at end of previous figure
Spin ending when danced with R to R hand hold:
Man: At end of 7, raise R hand above Lady''s R shoulder and circle it quickly in a clockwise direction. Over steps 8-10, continue to circle R hand clockwise, then lower arm to lead lady back at the end of her turn.
Lady: Spin approx. 1 1/8 to R on RF underarm towards end of step 7. 8-10 side and slightly back to chasse LRL, turning 1/2 to R to end LF back in Open Position.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Rolling Off the Arm' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Jive'));
