-- Figure: Shoulder Spin (Jive)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Shoulder Spin',
                    (SELECT id FROM dance_type WHERE name = 'Jive'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Open Position',
                    'Open Position',
                    '["American Spin","Catapult","Change of Places Left to Right","Change of Places Right to Left","Chugging","Rolling Off the Arm"]',
                    '["Change of Places Left to Right","American Spin","Rolling Off the Arm","Miami Special","Chugging","Catapult","Link","Change of Hands Behind Back","Hip Bump","Stop and Go"]',
                    'Lady must take her weight well forward to lean against Man''s hand on her shoulder.
Retain position, placing L hand on Lady''s R shoulder. Towards end of step 13, increase tone in L arm and turn Lady L with pressure through L hand. Immediately release L hand contact to R to R hand hold.
Regain L to R or R to R hand hold at end of Lady''s turn.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
