-- Figure: Spanish Arms (Jive)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Spanish Arms',
                    (SELECT id FROM dance_type WHERE name = 'Jive'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Open Position, double hand hold',
                    'Open Position, double hand hold',
                    '["Change of Places Left to Right","Rolling Off the Arm","Spanish Arms","Windmill"]',
                    '["Link (release R to L hand hold as needed)","Change of Places Left to Right (release R to L hand hold as needed)","Change of Hands Behind Back (release R to L hand hold as needed)","Hip Bump (release R to L hand hold as needed)","American Spin (left to right hand hold)","Stop and Go (release R to L hand hold as needed)","Windmill (release R to L hand hold as needed)","Spanish Arms (release R to L hand hold as needed)","Rolling Off the Arm (with double hold or releasing L to R hand hold)","Toe Heel Swivels (release R to L hand hold as needed)"]',
                    'Spin Ending to Spanish Arms:
Man: towards end of step 5, give a stronger pull with R hand, then immediately release R to L hand hold on steps 6-8 Compact chasse RLR, making no turn, continue to turn Lady to R under raised L arm and lower arm at end of Lady''s turn. End in Open Position.
Lady: Spin approx. a complete turn to R on RF underarm towards end of step 5. Steps 6-8 LF side and slightly back to chasse LRL, turning 1/2 to L to end LF back in Open Position.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
