-- Figure: Stop and Go (Jive)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Stop and Go',
                    (SELECT id FROM dance_type WHERE name = 'Jive'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Open Position',
                    'Open Position',
                    '["American Spin","Catapult","Change of Hands Behind Back","Change of Places Left to Right","Chugging","Fallaway Throwaway","Hip Bump","Shoulder Spin","Simple Spin","Spanish Arms","Stop and Go","Windmill"]',
                    '["Link","Change of Places Left to Right","Change of Hands Behind Back","Hip Bump","American Spin (with L to R hand hold)","Stop and Go"]',
                    'It could be danced without hold during lady''s turns.
Man will lead lady strongly with L hand to turn L on 3, immediately releasing hold, placing R hand on her back to check her turn on 5.
Man will lead her strongly with RH to turn R on 8, immediately releasing R hand contact, regaining L to R hand hold at the end of her turn.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

