-- Figure: ToeHeel Swivels (Jive)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'ToeHeel Swivels',
                    (SELECT id FROM dance_type WHERE name = 'Jive'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'LF',
                    'Open Position',
                    'Open Position',
                    '["Change of Places Left to Right","Spanish Arms","Windmill"]',
                    '["Fallaway Rock (step 3-8 of Fallway Rock","regain normal hold on 2nd chasse)","Fallaway Throwaway (step 3-8 Fallaway Throwaway)","Change of Places Right to Left","Stalking Walks","Flicks and Break (step 3-20","retain double hold throughout)"]',
                    'The turn on the swiveling foot may be a little less than specified turn above.
Alternative timing for swivels steps 3-8: QQS QQS
Combination timing (repeating 3-8 once) from step 1: QQ QQS QQS QQQ QQQ
"Break" follow:
Q: Hold the position from step 8 for an extra 3/4 beat - Man weight on RF, Lady LF
a: Replace part weight to LF (Lady RF) in PP (ball of foot) 1/4 beat
Q: Replace weight to RF (Lady LF) in PP (ball, flat) 1 beat
Then, follow step 3-8 of Fallaway Throwaway of Change of Places R to L.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

