-- Figure: Hand To Hand (Rumba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Hand To Hand',
                    (SELECT id FROM dance_type WHERE name = 'Rumba'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'RF',
                    'Closed Position',
                    'Open Position',
                    '["Closed Position","Cuban Rock LF","Hand To Hand RSP","New York LSP","Progressive Walks Forward in RSP","Progressive Walks Forward in Right Shadow Position","Shoulder To Shoulder Left Side","Side Step To Left commenced with LF","Side Step To Right commenced with RF","Spot or Switch Turn To R (Lady to L)","Syncopated Cuban Rocks RF","Underarm Turn To L"]',
                    '["Basic Movements: Open","Basic Movements: Closed","New York LSP","Spot or Switch Turn To R (Lady to L)","Underarm Turn To L","Hand To Hand RSP","Side Step To Left commenced with LF","Side Step To Right commenced with LF","Cuban Rock LF","Fan","Progressive Walks Forward in LSP (no turn on 2&3)","Rope Spinning","Syncopated Cuban Rock LF"]',
                    'It appears sharper if step 3 is danced fwd, then turn to end to side, facing partner.
Another option is to dance 4 1 fwd step and turn 1/2 at end of count "1", sharper.
Variation: end of count "4" do not turn and do 1/2 turn at end of count "1", sharper.
Hand To Hand RSP: may end in Open PP (1/8 over 2 & 3)
RSP could be retained, making no turn over 2 &3 and taking step 3 forward to follow with Progressive Walks Forward.
More advanced: step 3 may be taken fwd in line with RF, then turn 1/2 to R to end LF back in LSP having release R to L hand hold and taken L to R hand hold. (Lady opposite.)
Alternative hold: Can start with Normal hold. Man allow R hand to slide further around Lady''s back on step 1, releasing hold with L hand.
Lady slide L hand naturally across Man''s shoulder.
When following with Hand To Hand LSP, Man places L hand on Lady''s back, releasing R hand hold at end of step 3, while Lady rests R hand lightly across Man''s L shoulder.
Man''s hand on Lady''s back is just below her shoulder blade.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

