-- Figure: Natural Top (Rumba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Natural Top',
                    (SELECT id FROM dance_type WHERE name = 'Rumba'),
                    true,
                    'RF',
                    'LF',
                    'LF',
                    'LF',
                    'Closed Position',
                    'Closed Position',
                    '["Basic Movements: Closed","Basic Movements: Open","Progressive Walks Back","Underarm Turn To L"]',
                    '["Basic Movements: Open","Basic Movements: Closed","Fan","Natural Opening Out Movement (last step","Man leads Lady towards his R side)","Opening Out To Right And Left","Closed Hip Twist (last step","Man leads Lady towards his R side)","Spiral (last step","Man leads Lady towards his R side)","Rope Spinning (last step","Man leads Lady towards his R side)","Hockey Stick (4-6 following step 6 of Natural Top)","Advanced Hip Twists (continue to turn a further 1/8 (up to 3/8) R on step 9","Man taking last step fwd in line with LF towards Lady R side)","Continuous Hip Twists (continue to turn a further 1/8 (up to 3/8) R on step 9","Man taking last step fwd in line with LF towards Lady R side)","Circular Hip Twists (continue to turn a further 1/8 (up to 3/8) R on step 9","Man taking last step fwd in line with LF towards Lady R side)"]',
                    'Start in Closed Position. Circle imaginary spot in the center.
Because of the continuous turn, knees will not straighten fully on 1-8. so only a slight, natural hip movement is used.
Three steps of Natural Top may be danced, 7-9.
Gold Variation:
While dancing steps 4-5, lead Lady to turn L under raised L arm having release R hand hold.
Lady RF fwd and slightly across LF, turning 1/4 L on step 4 (count "2*), then continue to turn L on RF and step to side on LF almost facing partner on step 5 (count "3").
Get into normal hold and continue with 6-9 of Natural Top (Lady''s turn between steps 4&5 depends on Man''s turn.)'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

