-- Figure: New York (Rumba)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'New York',
    (SELECT id FROM dance_type WHERE name = 'Rumba'),
    true,
    'LF',
    'RF',
    'RF',
    'RF',
    'Open CPP',
    'Open CPP',
    '["Advanced Hip Twists","Alemana","Basic Movements: Closed","Closed Hip Twist","Cuban Rocks RF","Curl","Fencing","Hand To Hand LSP","Hockey Stick","New York RSP","Open Hip Twist","Progressive Walks Forward in LSP","Rope Spinning","Shoulder To Shoulder Right Side","Side Step To Right commenced with RF","Spiral","Spot or Switch Turn to L (Lady to R)","Syncopated Cuban Rock LF","Three Alemanas","Underarm Turn To R"]',
    '["Side Step To Left commenced with RF","New York LSP (when ending in Open PP)","Spot or Switch Turn to L (Lady to R) (when ending in Open PP)","Basic Movements: Open (4-6","when ending facing partner)","Basic Movements: Closed (4-6","when ending facing partner)","Underarm Turn To R (when ending facing partner)","Hand To Hand LSP (when New York LSP ends facing partner)","Side Step To Right commenced with RF (when New York LSP ends facing partner)","Cuban Rocks RF (when New York LSP ends facing partner)","Fan (4-6","when New York LSP ends facing partner)","Progressive Walks Forward in RSP (overturned to end fwd in RSP)","Closed Hip Twist (4-6","when New York LSP ends facing partner)","Syncopated Cuban Rocks RF (when New York LSP ends facing partner)"]',
    'Increase tone in connecting arm and keep it with body when turning (over 1-5). Note: RSP may be achieved after New York LSP by turning 1/8 more between step 3 of New York LSP and 1 of the next figure, to follow with Progressive Walks Forward. New York LSP may also be danced from Progressive Walks Forward in LSP (no turn on step 1 of New York LSP).'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

