-- Figure: ClosedWing (Waltz)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'ClosedWing',
    (SELECT id FROM dance_type WHERE name = 'Waltz'),
    true,
    'RF',
    'LF',
    'LF',
    'LF',
    'Closed Position',
    'Closed Position',
    '["Basic Weave","Chasse From Promenade Position","Closed Telemark","Outside Change","Turning Lock","Weave From Promenade Position"]',
    '["Closed Telemark (taking step 1 in CBMP OP on L side)","Open Telemark (taking step 1 in CBMP OP on L side)","Double Reverse Spin (taking step 1 in CBMP OP on L side)","Progressive Chasse To R (taking step 1 in CBMP OP on L side)","Reverse Turn (taking step 1 in CBMP OP on L side)","Fallaway Reverse And Slip Pivot","Whisk (if ended DW)"]',
    'Keep upward balanced poised position, don''t try to pull hip back to get around. This step is not too big. Keep it underneath body. (Man is not moving anywhere) Lady keeps her head upward and leftward on step 3 and keep her poise back. L leg goes ahead of body to Wing position. Try not to think body rotating. Think about sway. Try to keep shoulders parallel to partner.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'ClosedWing' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'ClosedWing' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));

