-- Figure: Hover Corte (Waltz)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Hover Corte',
    (SELECT id FROM dance_type WHERE name = 'Waltz'),
    true,
    'RF',
    'RF',
    'LF',
    'LF',
    'Closed Position',
    'Open Position',
    '["Closed Impetus","Natural Spin Turn","Outside Spin","Reverse Turn"]',
    '["Back Lock","Outside Change","Fallaway Whisk","Back Whisk","Outside Spin"]',
    'Options: keep head closed or open to PP (especially when dancing extra bar of music). Big step. Swing forward. Whole R side to Man, stretch. To create big shape, breathe the frame. After stepping RF forward, turning body from bottom to up, feet, hip, upper toros, and lastly head (articulate head). Really delay head, slow. Feels like head isn''t finishing till way into next step. Then articulate LF coming out. Do not shape from lower waist area. Think about high jump, "up and over", pick up center. When developing the shape, do not take arms back, leave arms to Man, extend. Count 3 4 5: RF moves towards LF | Towards alignment of 6 | T LF and pressure on IE T RF | Continue to turn body on step 2 | Sway(R R R) | -. Articulate LF coming out. soft knees, prepare next step by controlled lowering of knees. Count 1: RF fwd in CBMP, OP | Facing DC against LOD | H | - | Sway(S) | CBM | -.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Hover Corte' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Hover Corte' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));

