-- Figure: Weave from PP (after Open Impetus Turn) (Waltz)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Weave from PP (after Open Impetus Turn)',
    (SELECT id FROM dance_type WHERE name = 'Waltz'),
    true,
    'RF',
    'RF',
    'LF',
    'LF',
    'Promenade Position',
    'Closed Position',
    '["Back Whisk","Contra Check","Fallaway Whisk","Open Impetus","Open Telemark","Outside Change","Turning Lock","Turning Lock to R","Whisk"]',
    '["Natural Spin Turn","Natural Turn","Wing (when ended in PP)","Left Whisk (when ended in PP)","Chasse From Promenade Position (when ended in PP)","Closed Wing","Cross Hesitation (when ended in PP)"]',
    'Man: 1/8 to L can be made between 2-3, so 4-5 may be taken BLOD. Less turn can be made on Whisk to end facing LOD, or the Open Impetus could be used an an entry, when the body would be facing LOD. Then, the alignment will be like the Weave in Foxtrot. This may end in PP, same as Outside change to PP from step 4.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Weave from PP (after Open Impetus Turn)' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Weave from PP (after Open Impetus Turn)' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));

