    (SELECT id FROM dance_figure WHERE name = 'Weave from PP (after Open Impetus Turn)' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz')),
    4,
    '1',
    'FOLLOWER',
    'LF',
    'LF fwd in PP and CBMP, Facing DC, traveling DC, start to turn L, CBM, start to rise e/o 1',
    'WF',
    'DC',
    ''
);
INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    '948fc375-bf15-392e-9ff1-d9d027466986',
    '7714c314-8f64-391d-b7e9-e01fcc5ec185',
    'Both step 1 and 2, think about stepping straight forward, forward, do not curve into Man, do not turn too early (don''t turn late either). Legs are ahead of body. Big step. Stay connected with Man. Work the R side a lot to stay with Man.',
    1
);
INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    '9c883c35-9fbd-319c-af4c-9a79ec7bc7a9',
    '7714c314-8f64-391d-b7e9-e01fcc5ec185',
    'Shaping: starting from PP (L hip up). on count 1, R hip begins to pick up.',
    2
);
INSERT INTO dance_figure_step (id, dance_figure_id, step_number, timing, role, foot, action, footwork, alignment, amount_of_turn)
VALUES (
    '8584caef-94c3-322d-823e-8b7acc1305c5',
    (SELECT id FROM dance_figure WHERE name = 'Weave from PP (after Open Impetus Turn)' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz')),
    5,
    '2',
    'FOLLOWER',
    'RF',
    'RF to side and slightly back, BDC, T, 1/4 to half turn btwn 1-2, Cont to rise on 2 and 3',
    'T',
    'BDC',
    '1/4 to half turn btwn 1-2'
);
INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    '43b1b7ff-7b48-3927-a6a0-849bb0293e4b',
    '8584caef-94c3-322d-823e-8b7acc1305c5',
    'Swing leg strongly forward, big step. Don''t turn right away. Head traveling forward with the RF first, Get weight on RF, balance on RF, then turn body and head. Don''t lose R side. Give R side and hip to Man. Do not just rise and let body fall backward. Think about going forward along the curve which will give you better rotation, give Man more space.',
    1
);
INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    '76a548a3-621b-3a48-907c-f5168b9808a2',
    '8584caef-94c3-322d-823e-8b7acc1305c5',
    'At end of this step, R hip is swung up at its maximum. Think about "swing up and hover".',
    2
);
INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    'b03f25b3-960f-3d15-b767-e10e53f6427b',
    '8584caef-94c3-322d-823e-8b7acc1305c5',
    'Always stay on left side (Man''s right). Give R side to Man. Stretch, create bigger, fuller shape.',
    3
);
INSERT INTO dance_figure_step (id, dance_figure_id, step_number, timing, role, foot, action, footwork, alignment, amount_of_turn)
