-- Figure: Closed Telemark (Quickstep)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Closed Telemark',
    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
    true,
    'LF',
    'LF',
    'RF',
    'RF',
    'Closed Position',
    'Closed Position',
    '["Double Reverse Spin","Heel Pivot (Quarter Turn To Left)","Reverse Pivot"]',
    '["Running Right Turn","Natural Turn And Back Lock","Natural Pivot Turn","Natural Spin Turn","Natural Turn With Hesitation","Natural Turn","Quarter Turn to Right","Forward Lock","Fish Tail","Four Quick Run","Six Quick Run"]',
    'Footwork same as Walz Closed Telemark. Possible timings: SSSS, SQQS, QQSS (after a reverse pivot). Leader: LF forward (FDC, HT, start to turn L), sway, CBM, rise; RF to side (almost BLOD, T, slightly less than 3/8 between 1-2), sway left, up; LF side forward (DW, TH, slightly over 3/8 between 2-3), sway, up, lower; RF forward in CBMP, OP, DW, H, sway. Follower: RF back (BDC, TH, start to turn L), strong big step, CBM; LF closes to RF (Heel Turn, LOD, HT, 3/8 between 1-2), sway right, continue rise; RF side back (BDW, TH, 3/8 between 2-3), sway, up, lower; LF back in CBMP (BDW, T), sway. Head shape: right then left; keep contact with man; leave room for man''s next step; lower before driving into next step.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Closed Telemark' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Closed Telemark' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));

