-- Figure: Natural Spin Turn (Quickstep)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Natural Spin Turn',
    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
    true,
    'RF',
    'RF',
    'LF',
    'RF',
    'Closed Position',
    'Closed Position',
    '["Closed Telemark","Cross Chasse","Fish Tail","Forward Lock","Four Quick Run","Quarter Turn to Left (Heel Pivot)","Natural Pivot Turn","Natural Turn","Progressive Chasse","Running Finish","Running Right Turn","Tipple Chasse To Right","V6","Zig-Zag","Back Lock And Running Finish"]',
    '["Progressive Chasse","Reverse Pivot","Quarter Turn to Left (Heel Pivot)","Four Quick Run","V6","Six Quick Run","Hover Corte"]',
    'Rise on toes, it will help to bring the feet together on 3rd step. Have continuous swing of the leg through the step. When connecting with V6 (QQS lock step), the footwork for this count becomes THT. Keep head to far left, follow L elbow, outside circle. Extend. Collect center back to the spine. Have the middle of body go forward to Man and keep leg moving, but leaving head behind which creates more extension, then head catches up. Don''t pause body movement. Simply just leave head behind.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

