-- Figure: Progressive Chassé to Right (Waltz)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Progressive Chassé to Right',
                    (SELECT id FROM dance_type WHERE name = 'Waltz'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Outside Partner Position',
                    '["Change of Direction","Double Reverse Spin","Heel Pivot (Quarter Turn To Left)","Natural Turn With Hesitation","Reverse Pivot"]',
                    '["Closed Impetus","Back Lock","Tipple Chasse To Right","Running Finish","Four Quick Run (when preceding figure ends DC or LOD)","V6 (6-12","when preceding figure ends DC or LOD)","Tipsy To R","Six Quick Run (when preceding figure ends DC)"]',
                    'Bronze: The Progressive Chassé to R could be started facing LOD and ended backing DW (3/8 turn) when the amounts of turn would be:
Man: 1/4 between 1-2, 1/8 between 2-3 (body turns less), no further turn
Lady: 3/8 between 1-2 (body turns less), slight body turn to L on 3, no further turn.
Silver and Gold: Started facing DC and ended backing LOD (3/8 turn), or started facing DC and ending backing DC (1/2 turn). If 1/2 turn is mad the amounts of turn will be:
Man: 1/4 between 1-2, 1/8 between 2-3, 1/8 between 4-5
Lady: 3/8 between 1-2 (body turns less). Body completes turn on 3, 1/8 between 3-4 (body turns less)'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Progressive Chassé to Right' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));
