-- Figure: Rumba Cross (Quickstep)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Rumba Cross',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Facing LOD',
                    'Backing LOD',
                    '["Natural Pivot Turn","Natural Turn"]',
                    '["Running Right Turn (5-11 of Running Right Turn","RF fwd","S","into Tipsy to L)","Rumba Cross"]',
                    'If preceding the Rumba Cross with 1-5 Natural Turn, a sway to L would be used on step 5 which could be held at the beginning of step 1 of the Rumba Cross. This sway assists in maintaining forward movement through the turn. The Rumba Cross may be danced twice.
When preceding with a Natural Pivot Turn, S is added before this Q.
Lady''s description includes mental forward feeling, hip to Man, etc.
Do not level up shoulders and hips, leaving R side positive. R knee is forward over the toe, completely balanced on RF.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Rumba Cross' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));
