-- Figure: Curved Feather (Foxtrot)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Curved Feather',
                    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'LF',
                    'Promenade Position',
                    'Facing LOD',
                    NULL,
                    NULL,
                    'Not listed in "gray book", but often danced.
Stretching does not mean turning shoulder to right. It''s R side upward stretch.
Small step.
Do not allow stomach to relax. R side lengthen.
Keep individual balance.'
                )
