-- Figure: Curved Feather to Back Feather (Foxtrot)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Curved Feather to Back Feather',
    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
    true,
    'RF',
    'RF',
    'LF',
    'LF',
    'Closed Position',
    'Closed Position',
    '["Open Impetus Turn","Outside Swivel","Reverse Wave","Three Step"]',
    '["Closed Impetus and Feather Finish","Open Impetus Turn"]',
    'Typically, continue with Feather Finish SQQ. If Man shapes, Lady turn her head to R on QQ, keep ribs to Man. Lady can lower her R heel on step 2. Head to L. Hip and body rotating to R, follow Man''s hips, rotate hip to Man, connected with Man, hip is still in front of Man, not to the side of Man''s hip. Leave RF loosely in front, do not stick R leg too early. Prepare to really use LF to push for next RF fwd step. This is the circling movement action, get weight into heel and then push forward. When swing on Q: do not dip shoulder low, keep shoulders flat, swing forward, traveling. Give center to Man, shape. Breathe, release so body does not stiff up.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Curved Feather to Back Feather' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Curved Feather to Back Feather' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));

