-- Figure: Fallaway Reverse and Slip Pivot (Foxtrot)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Fallaway Reverse and Slip Pivot',
    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
    true,
    'LF',
    'LF',
    'RF',
    'RF',
    'Closed Position',
    'Backing Line of Dance',
    '["Basic Weave","Bounce Fallaway with Weave Ending","Closed Impetus and Feather Finish","Fallaway Reverse and Slip Pivot","Feather Step","Hover Cross","Hover Feather","Natural Hover Telemark","Natural Telemark","Natural Twist Turn","Natural Weave","Natural Zig-Zag from PP","Open Telemark and Feather Ending","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Reverse Turn","Top Spin","Weave from PP"]',
    '["Change Of Direction","Hover Telemark","Reverse Wave","Fallaway Reverse and Slip Pivot","Basic Weave (At corner)","Open Telemark and Feather Ending (At corner)"]',
    'Different timings that can be used on this figure: SQQS, SQQ&, SQ&Q, S&QQ, QQQQ. (S: 2 beats, Q: 1 beat, &: 1/2 beat) When this figure is danced into corner, start DW or LOD to follow with a Reverse figure, DC of new LOD. Depending on the previous alignment and choreography, e.g. if starting DW into corner, the 2nd step could be taken diagonal (instead of moving along LOD)'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Fallaway Reverse and Slip Pivot' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));
