-- Figure: Hover Feather (Foxtrot)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Hover Feather',
                    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'RF',
                    'Closed Position',
                    'Closed Position',
                    '["Hover Telemark","Natural Turn","Reverse Wave"]',
                    '["Three Step","Reverse Turn","Change Of Direction","Closed Telemark","Open Telemark and Feather Ending","Hover Telemark","Reverse Wave","Top Spin","Outside Swivel","Fallaway Reverse and Slip Pivot","Bounce Fallaway with Weave Ending"]',
                    'Note -- Body will overturn slightly to R on preceding Heel Pull. the footwork of the Heel Pull will be: 1. TH; 2 H; IE of foot, whole foot, then T of RF and pressure on IE of T of LF.
Note -- Body will overturn to R on preceding Brush step. The Lady will rise from the ball of LF at the end of the Brush step. The L heel does not touch the floor.
The Hover Feather is a Silver Level figure. This online reference gives a detailed description of the dance steps, including timing, footwork, alignment, and movement; steps diagram; a list of figures that may precede or follow the pattern; and videos providing instruction and demonstration of the figure, techniques and practice routines that include it.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Hover Feather' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Hover Feather' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));

