INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Hover Telemark',
    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
    true,
    'LF',
    'LF',
    'RF',
    'LF',
    'Closed Position',
    'Promenade Position',
    '["Basic Weave","Bounce Fallaway with Weave Ending","Closed Impetus and Feather Finish","Fallaway Reverse and Slip Pivot","Feather Step","Hover Feather","Natural Hover Telemark","Natural Telemark","Natural Twist Turn","Natural Weave","Natural Zig-Zag from PP","Open Telemark and Feather Ending","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Reverse Turn","Top Spin","Weave from PP"]',
    '["Feather Step (step 1 in CBMP OP)","Basic Weave (LF fwd in line with partner on toe into overturned Basic Weave)","Hover Feather (steps 1-2 counted SS can be followed by Hover Feather)","Natural Turn (at corner)","Natural Weave (at corner)","Natural Telemark (at corner)","Open Telemark","Natural Turn","Outside Swivel and Feather Ending (at corner)","Natural Twist Turn (at corner)","Natural Zig-Zag from PP (at corner)","Natural Hover Telemark (at corner)","Curved Feather to Back Feather (at corner)"]',
    'Hover Telemark can finish in Promenade Position. See Hover Telemark to PP.'
)
