-- Figure: Quick Open Reverse (Foxtrot)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Quick Open Reverse',
                    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Open Position',
                    NULL,
                    NULL,
                    'Curve the step. Connect R shoulder down to R hip (turning the dial). Preparing for L turn (Lady is inside of turn): Lower part of body is rotary, upper body is on sway plane. For left turning figures, upper body turns less. L shoulder positive.
Keep left side strongly to the Man all through the steps.
The movement is still same direction back, foot is pointing LOD.
Swing L hip and L side through an upward diagonal (push from the R hip), do not put head weight forward too quickly. Feel the lightness. Body stretched.
Changing from L side positive to R side positive.
Feather ending.
Lengthen the R side. Take head to L. Turn the feet. Giving/keeping upper body and arms to partner.
Body position is strongly to the right, head balance on the left.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

