-- Figure: Closed Promenade (Tango)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Closed Promenade',
    (SELECT id FROM dance_type WHERE name = 'Tango'),
    true,
    'LF',
    'LF',
    'RF',
    'LF',
    'Closed Position',
    'Closed Position',
    '["Basic Reverse Turn","Chase","Contra Check","Fallaway Four Step","Fallaway Promenade","Five Step","Four Step","Natural Promenade Turn","Natural Twist Turn","Open Finish","Open Promenade","Open Reverse Turn","Lady In Line","Open Reverse Turn","Lady Outside","Oversway","Progressive Link","Progressive Side Step Reverse Turn","Basic Reverse Turn","Fallaway Reverse and Slip Pivot","Four Step","Outside Swivel","Four Step Change","Brush Tap","Fallaway Four Step","Oversway","Five Step","Contra Check"]',
    '["Walk (LF)","Progressive Side Step","Progressive Link","Back Corte","LF Rock","Open Reverse Turn","Lady Outside","Open Reverse Turn","Lady In Line","Progressive Side Step Reverse Turn","Reverse Outside Swivel","Basic Reverse Turn","Fallaway Reverse and Slip Pivot","Four Step","Outside Swivel","Four Step Change","Brush Tap","Fallaway Four Step","Oversway","Five Step","Contra Check"]',
    'Man''s first step needs to be side, not forward, i.e., he does not turn his left foot out to point the direction he is stepping.\nBe in sync with lady, flexing knee to start shifting weight (don''t tilt body though), moving across the feet.\nRotate right hip to close the lady up.\nDo not fall forward with shoulders and upper body.\nThe feeling is that Lady is dancing at Man''s right edge. Upper body is very much behind Man''s hip.\nStay connected with Man, keep R side fwd rotated to Man.\nRF Toe in line with LF. "side" step is like a forward step. Move "with" the Man.\nDo not slide foot. Left foot roll off and end on ball of front of LF, then lift and place LF close to RF (could have a very small gap), slightly forward.\nSofter and smoother step, not the sharp accent.\nBack to starting foot position.\nNote:\nMan may turn square to the lady in step 3, to end backing DC. Footwork for man would then be IE BH and for the lady IE of foot.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Closed Promenade' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Tango'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Closed Promenade' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Tango'));

