-- Figure: Open Finish (Tango)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Open Finish',
                    (SELECT id FROM dance_type WHERE name = 'Tango'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'LF',
                    'Promenade Position',
                    'Open Position',
                    '["LF Rock","Walk (LF)","Progressive Side Step","Progressive Link","Open Reverse Turn","Lady Outside","Open Reverse Turn","Lady In Line","Progressive Side Step Reverse Turn","Reverse Outside Swivel","Basic Reverse Turn","Fallaway Reverse and Slip Pivot","Four Step","Four Step Change","Brush Tap","Fallaway Four Step","Oversway","Five Step","Back Corte","LF Rock","Outside Swivel","Closed Promenade","Open Promenade","Natural Promenade Turn","Promenade Link","Back Open Promenade","Fallaway Promenade"]',
                    '["Walk (LF)","Progressive Side Step","Progressive Link","Open Reverse Turn","Lady Outside","Open Reverse Turn","Lady In Line","Progressive Side Step Reverse Turn","Reverse Outside Swivel","Basic Reverse Turn","Fallaway Reverse and Slip Pivot","Four Step","Four Step Change","Brush Tap","Fallaway Four Step","Oversway","Five Step","Back Corte","LF Rock","Outside Swivel","Closed Promenade","Open Promenade","Natural Promenade Turn","Promenade Link","Back Open Promenade","Fallaway Promenade"]',
                    'Closed Finish
Finish with feet together (LF is slightly forward, but two feet are closed to each other). e.g. Closed Promenade 
Open Finish
Leader
Q: RF fwd | start from PP
Q: LF side and slightly fwd | Pointing between Wall and DW | IE of foot
S: RF fwd in CBMP, OP | Between wall and DW | H
Follower
Q: LF fwd | start from PP
Q: RF to side and slightly back | Backing between Wall and DW | IE of BH
S: LF back in CBMP | between Wall and DW | B
Rotate to the R, take R hip back, L leg back in CBMP, landing OE of front of LF.
Keep hips toward Man.
Allow upper body to rotate to R, without becoming back weighted. Never allow body to go behind the hips. 
Practice to not be back weighted: should be easy to do rocking action, keep weight on ball of foot. 
The step becomes BH when next step is a back step. 
It could also be followed an Outside Swivel, in which case heel does not drop, keep weight on ball of LF, L leg/foot compresses and Lady comes back out with a forward step on RF and swivels. 
If doing RF flick, LF heel may kiss the floor but still keep weight more forward and not let upper body fall back behind hips.
Technique Notes
Other alignments and directions may be used.
Amount of turn: slightly less turn to L will be made on a figure when changing a Closed Finish to Open Finish. Although normal turn will be made when following with a curve or turn to L, e.g. Walk on LF, or Outside Swivel turning L from Open Finish (method 2).
Follows can be moving forward, back or to side. When stepping forward from and Open Finish, step 1 will not be taken in CBMP.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Open Finish' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Tango'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Open Finish' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Tango'));

