-- Figure: Progressive Side Step Reverse Turn (Tango)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Progressive Side Step Reverse Turn',
                    (SELECT id FROM dance_type WHERE name = 'Tango'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Open Position',
                    'Closed Position',
                    '["Back Corte","Brush Tap","Closed Promenade","Fallaway Reverse and Slip Pivot","Four Step Change","Open Finish","Open Promenade","Outside Swivel","Promenade Link","Reverse Outside Swivel","Rock Turn","Walk"]',
                    '["Walk","Progressive Side Step","Progressive Link","Back Corte","LF Rock","Closed Promenade","Open Promenade","Natural Promenade Turn","Promenade Link","Back Open Promenade","Fallaway Promenade","Four Step","Outside Swivel","Four Step Change","Brush Tap","Fallaway Four Step","Five Step","Contra Check"]',
                    'Total amount of Turn: 3/4 to L
After steps 1-4, the following endings may be used
- Back Corté SQQS
- Rock on LF, Rock on RF, Back Corté QQS, QQS, SQQS
Lady: Keep head strongly left throughout, keeps shoulders parallel, not rotating through shoulders. Keep everything in the base.
The movement of this step is a bit more smooth (not as staccato as Closed Promenade, for example.)'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Progressive Side Step Reverse Turn' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Tango'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Progressive Side Step Reverse Turn' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Tango'));

