-- Figure: Contra Check (Viennese Waltz)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Contra Check',
    (SELECT id FROM dance_type WHERE name = 'Viennese Waltz'),
    true,
    'LF',
    'RF',
    'RF',
    'RF',
    'Closed Position facing LOD',
    'Backing against LOD',
    '["Reverse Fleckerl","Reverse Turn"]',
    '["Natural Fleckerl","Natural Turn"]',
    'Commence facing LOD or other alignments. The Viennese Waltz Reverse Turn is a Gold Level figure. Man commences with a forward step in CBMP, weight split, extending right side forward without hip rotation. Transfer weight back to RF backing against LOD, then step back with LF pivoting on toe, ending facing against LOD. Lady mirrors with a back step in CBMP, then transfers weight forward to LF, and finally steps forward between partner''s feet ending backing against LOD. Do not peel left side off, keep head space relative to partner, and maintain contact without lifting toe. LF may stay flat or release heel slightly. Stay left to partner, head follows left elbow, look at RF over shoulder.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
