-- Figure: Reverse Fleckerl (Viennese Waltz)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Reverse Fleckerl',
    (SELECT id FROM dance_type WHERE name = 'Viennese Waltz'),
    true,
    'LF',
    'RF',
    'RF',
    'RF',
    'BLOD (any other alignment is possible)',
    'Facing LOD (varies by step)',
    '["Reverse Fleckerl","Reverse Turn"]',
    '["Contra Check","Reverse Turn","Reverse Fleckerl"]',
    'The amount of turn: can do 1 full turn up to 2 full turns (as shown above). For both Man and Lady, there is a strong rotation, so there must be a foot swivel on the ball of the flat foot on each step. Fleckerls are done on the spot, it doesn''t move around, focus on rotation. The power for the rotation does not come from upper body. Speed comes from feet and legs. When the steps are repeated, the Man will dance step 1 as lady''s step 4 (draw LF back to RF, L heel closes to inside edge of RF). Note: Commencing facing LOD (any other alignment is possible). This figure can turn 1 full turn or up to 2 turns, up to dancers.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
