-- Figure: Cross Swivel (Quickstep)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Cross Swivel',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'RF',
                    'Closed Position',
                    '',
                    '["Double Reverse Spin","Heel Pivot (Quarter Turn To Left)","Reverse Pivot"]',
                    '["Tipple Chasse To Right","Running Finish","Fish Tail","Tipsy To R (After LF back with Lady OP","TH","S","into Tipsy to R)"]',
                    'Alternative styling for Leader: RF to side, knees inward.
Leader technique notes: start to turn L, Sway(S), CBM.
Follower technique notes: Use hip joint to start the turn, standing knee (R knee) stays forward over the standing foot (RF), do not move the knee off the standing foot. Use ab muscle to pull to the back of foot, do not leave middle forward and shoulder weight back. Heel of RF does not lower until the turn is completed. Head is still left. At end of & there is "up" rise feeling before the next S lower to normal.
Follower styling note: Body forms a line, slanted straight to R, keep left side lifted. Give R side to Man. Stay connected. Turn head to R. At end of & rise in body before next S to lower to normal (not "sinking down").'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Cross Swivel' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Cross Swivel' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));

