-- Figure: Double ReverseSpin (Quickstep)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Double ReverseSpin',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'RF',
                    'Closed Position',
                    'Closed Position',
                    '["Heel Pivot (Quarter Turn To Left)","Natural Turn With Hesitation","Reverse Pivot"]',
                    '["Chasse Reverse Turn","Progressive Chasse To Right","Double Reverse Spin","Cross Chasse","Zig-Zag","Back Lock And Running Finish","Quick Open Reverse","Closed Telemark","Cross Swivel","Tipsy To R (LF fwd","H","S into Tipsy to R)","Change of Direction"]',
                    'The Double Reverse Spin may be started LOD (chart above), DC, or DW. When starting DW, lady: before stepping RF back, turn knee 1/8 to L, step back, so RF is stepping straight down LOD. Body feel quite twisted. The step 1 of both Double Reverse Spin and Progressive Chasse to Right feel the same, the difference is the next step. For Double Reverse Spin: Man steps DC, toward Lady''s left shoulder (not her sternum). For Progressive Chasse to Right, Man moves toward LOD, making Lady to step pass her LF to the side. Double Reverse Spin is a traveling step, first Man goes, then Lady goes. It needs to move down the floor. The amount of turn may vary between 3/4 and a whole turn.
Complete Turn:
step 1-2: Man 3/8, Lady: 1/2
step 2-3: Man 5/8: Lady: 3/8
step 3-4: lady: 1/8
3/4 Turn:
step 1-2: Man 1/4 (or 3/8), Lady: 3/8
step 2-3: Man: 1/2 (or 3/8), Lady: 1/4
step 3-4: Lady 1/8'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Double ReverseSpin' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Double ReverseSpin' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));

