-- Figure: Running Finish (Waltz)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Running Finish',
                    (SELECT id FROM dance_type WHERE name = 'Waltz'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Closed Position',
                    '["Back Lock","Cross Swivel","Hover Corte","Natural Turn And Back Lock","Progressive Chasse To Right"]',
                    '["Forward Lock","Natural Turn And Back Lock","Natural Pivot Turn","Natural Spin Turn","Natural Turn With Hesitation","Natural Turn","Quick Open Reverse","Fish Tail","Four Quick Run","V6","Tipsy To L","Six Quick Run"]',
                    'Timing can also be: QQSS
Can be commenced in other alignments, e.g. starting BLOD, ending DC.
Man may turn 1/4 between 1-2 when a facing alignment would be used. Lady would turn 1/8 between 1-2 and 1/8 between 2-3.'
                )
