-- Figure: Six QuickRun (Quickstep)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Six QuickRun',
    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
    true,
    'RF',
    'LF',
    'LF',
    'LF',
    '',
    '',
    '["Closed Impetus","Closed Telemark","Fish Tail","Forward Lock","Four Quick Run","Hover Corte","Natural Spin Turn","Progressive Chasse","Progressive Chasse To Right","Quarter Turn to Right","Running Finish","Tipple Chasse To Right","V6"]',
    '["Natural Turn (start OP)","Fish Tail","Tipsy To L (into 2-12 V6 DC or 2-5 Back Lock down LOD.)"]',
    'Leader completes the turn with feet between 1-2, making 2nd step ''side and slightly back''. ... Lady completes the turn with feet between 1-2, making 2nd step ''side and slightly back''. ... Traveling backwards in outside partner position: Think about lengthening/stretching/swinging the right side as Lady takes the head left, not rotating the body. If the body just rotates, the center tends to go backwards. Arms belong to partner. Head left to balance. Stretch body and stay connected to Man.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Six QuickRun' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Six QuickRun' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));

