-- Figure: Tipsy To Right and Left (Quickstep)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Tipsy To Right and Left',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'LF',
                    'Closed Position',
                    'Closed Position',
                    '["Back Lock","Cross Swivel","Double Reverse Spin","Hover Corte","Natural Turn","Natural Turn And Back Lock","Progressive Chasse To Right","Reverse Pivot","Tipple Chasse To Right","Tipsy To L"]',
                    '["Fish Tail","Forward Lock","Four Quick Run","Hover Corte","Progressive Chasse","Running Finish","Running Right Turn","Six Quick Run","Tipple Chasse To Right","V6"]',
                    'Compact figure, bright and bubbly. Light on knees, cushioned. knees and legs have compression.
Lady is outside of turn, step would be bigger than Tipsy to Left.
Head shapes into the turn Not only shape the body, make sure head goes with the body line (head does stay straight up) Stretch diagonal.
When shaping to left, right side stretched. Do not rotate the shoulders. Keep right side connection with Man. Follow Man''s hips. Articulate head back to Left.
Note: When a Tipsy is danced after a forward step on the LF any turn made will be to L. When it is danced after a step back on LF, any turn made will be to R.
Precede with a step forward on RF, OP in CBMP'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

