-- Figure: Quarter Turn toRight (Quickstep)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Quarter Turn toRight',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Open Position',
                    '["Closed Impetus","Fish Tail","Forward Lock","Hover Corte","Natural Spin Turn","Progressive Chasse","Progressive Chasse To Right","Quarter Turn to Right","Running Finish","Tipple Chasse To Right","Tipsy To L"]',
                    '["Running Right Turn","Natural Turn And Back Lock","Natural Pivot Turn","Natural Spin Turn","Natural Turn With Hesitation","Natural Turn","Forward Lock","Fish Tail","Quick Open Reverse (after 6-8 of V6 overturned to LOD)","Four Quick Run (at corner","LF back with Lady OP","TH","S","into Four Quick Run)","Tipsy To L (into 2-5 Back Lock down LOD)","Six Quick Run (LF back with Lady OP","TH","S","into Six Quick Run)"]',
                    'For side leading position: low center (hip, belly button area) is turned ~ 1/8 relative to feet, then upper body (sternum) is turned another 1/8.
Preceding Figures
Closed Impetus
Fish Tail
Forward Lock
Four Quick Run
Hover Corte
Natural Spin Turn
Progressive Chasse
Progressive Chasse To Right
Quarter Turn to Right
Running Finish
Tipple Chasse To Right
Tipsy To L

Following Figures
Running Right Turn
Natural Turn And Back Lock
Natural Pivot Turn
Natural Spin Turn
Natural Turn With Hesitation
Natural Turn
Quarter Turn to Right
Forward Lock
Fish Tail
Quick Open Reverse (after 6-8 of V6 overturned to LOD)
Four Quick Run (at corner, LF back with Lady OP, TH, S, into Four Quick Run)
Tipsy To L (into 2-5 Back Lock down LOD)
Six Quick Run (LF back with Lady OP, TH, S, into Six Quick Run)'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

