-- Figure: Zig-Zag Back Lock And Running Finish (Quickstep)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Zig-Zag Back Lock And Running Finish',
    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
    true,
    'LF',
    'RF',
    'RF',
    'LF',
    'Closed Position',
    'Closed Position',
    '["Double Reverse Spin","Heel Pivot (Quarter Turn To Left)","Natural Turn","Reverse Pivot","Natural Turn"]',
    '["Natural Turn And Back Lock","Natural Pivot Turn","Natural Spin Turn","Natural Turn With Hesitation","Natural Turn","Forward Lock","Quick Open Reverse"]',
    'Could use the alternative Running Finish timing QQSS (7-10). Keep body parallel with Man during heel turn. After RF step back on step 3 CBMP, it will give room for Lady to move RF with heel lead (HT). With the plie position, lady and man will not bump knees. At heel turn: keep body forward, do not shift to right and get into Man''s space. Head could turn to right, but it needs to be clear. Turning head to right has the tendency to make lady more in front of Man, which is not good. Start by keeping the head to left. Keep knees flexed, keep head left during the lock. Keep right side stretched and connected with Man. During Running Finish, keep upward swing. Right side positive, don''t rotate right shoulder off Man. Head shape to R. Often, this is the start of Natural Turn. Big step.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Zig-Zag Back Lock And Running Finish' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Zig-Zag Back Lock And Running Finish' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));

