-- Figure: Alemana (Rumba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Alemana',
                    (SELECT id FROM dance_type WHERE name = 'Rumba'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Closed Position',
                    '["Advanced Hip Twists","Basic Movements: Open","Closed Hip Twist","Curl","Fan","Hockey Stick","Open Hip Twist","Opening Out From Reverse Top","Progressive Walks Forward","Spiral","Spot or Switch Turn to L (Lady to R)","Three Threes"]',
                    '["Basic Movements: Closed","Fan","Opening Out To Right And Left (Lady LF side on 6)","Hand To Hand RSP (when ending to side)","Side Step To Left commenced with LF (when ending to side)","Side Step To Right commenced with LF (when ending to side)","Cuban Rock LF (when ending to side)","Syncopated Cuban Rock LF (when ending to side)","New York LSP (when ending diagonally fwd in Open CPP)","Spot or Switch Turn To R (Lady to L) (when ending diagonally fwd in Open CPP)","Underarm Turn To L (when ending diagonally fwd in Open CPP)","Natural Opening Out Movement (when ending Lady fwd toards Man''s R side)","Closed Hip Twist (when ending Lady fwd toards Man''s R side)","Spiral (when ending Lady fwd toards Man''s R side)","Rope Spinning (when ending Lady fwd toards Man''s R side)","Progressive Walks Forward in Right Shadow Position (when ending R Shadow Position)"]',
                    'This is really a signature figure for Lady. Make it count!
Lady may use Extended Forward Walk on step 4.
Alemana may start in Fan Position or Open Position (Lady steps back on 1 instead of closing RF to LF, make a complete turn R over 4-6)
Alternative Finishing positions:
May and Lady end to side (could be in closed position)
Man steps in front of Lady, forcing her to step side instead of front.
Another option is to finish in Open Position: last step Man steps fwd, strongly hold hand and have Lady step back.
Man and Lady end diagonally fwd in Open CPP
Man 1/8 to R, on 6 stop Lady''s turn with L hand, Lady 1 1/8 R over 3-6.
Lady end fwd towards Man''s R Side (normal for continuing with Closed Hip Twist) - sort of true Alemana.
Man turns body slightly R on 6 to lead lady towards his R side. Lady LF fwd in line with RF.
Man LF slightly leftwards on the next step.
Man and Lady fwd towards partner''s R side
Man RF fwd in line with LF towards Lady''s R side
Lead next and last step as position 3.
Man may take up to 1/4 R over 5 & 6, adjusting Lady''s turn accordingly.
R Shadow Position
Man leads Lady towards R side as above
Continue to turn her R.
Lady ends LF back having made 1/2 turn R on LF during beat 1. Gain R Shadow Hold.
Alemana can be danced with R to R hand hold. Precedes with Hockey Stick or any figure ending in Open Position.
Then Man changes Lady''s R hand into his R hand on last step and release hold with L hand.
Lady makes a complete turn R on Alemana.
Man takes last step fwd i line with LF towards partner''s R side.
Lead next and Lady''s last step as # 3 position.
Man may take up to 1/4 R over 5 & 6, adjusting Lady''s turn accordingly.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

