-- Figure: Rumba Closed Basic Movements (Rumba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Rumba Closed Basic Movements',
                    (SELECT id FROM dance_type WHERE name = 'Rumba'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Closed Position',
                    '["Alemena","Basic Movements: Closed","Basic Movements: Open","Cuban Rock LF","Cuban Rocks RF","Cucarachas: LF","Cucarachas: RF","Fencing","Hand To Hand LSP","Hand To Hand RSP","Natural Opening Out Movement","Natural Top","New York LSP","New York RSP","Opening Out To Right And Left","Progressive Walks Back","Progressive Walks Forward","Progressive Walks Forward in LSP","Progressive Walks Forward in RSP","Progressive Walks Forward in Right Shadow Position","Reverse Top","Rope Spinning","Shoulder To Shoulder Left Side","Shoulder To Shoulder Right Side","Side Step To Left commenced with LF","Side Step To Left commenced with RF","Side Step To Right commenced with LF","Side Step To Right commenced with RF","Spot or Switch Turn to L (Lady to R)","Spot or Switch Turn To R (Lady to L)","Syncopated Cuban Rock LF","Syncopated Cuban Rocks RF","Three Alemanas","Three Threes","Underarm Turn To L","Underarm Turn To R"]',
                    '["Reverse Top","Basic Movements: Open (normal; or after 1-3 Closed Basic","follow with 4-6 Open Basic)","Basic Movements: Closed","New York LSP (having turned to Open CPP on last step)","Spot or Switch Turn To R (Lady to L)","Underarm Turn To L","Shoulder To Shoulder Left Side","Side Step To Left commenced with LF","Side Step To Right commenced with LF","Hand To Hand RSP","Cuban Rock LF","Fan","Syncopated Cuban Rocks RF","Natural Top (after 1-3 Closed Basic","Man step 3 LF side turning slightly R","Lady RF fwd)","Basic In Place","3 steps are danced in place with feet together","Closed Position","No Turn. This can be danced in place of Closed Basic Movements.","Alternative Basic","Closed Position","start with feet apart. Normal hold","L to R hand hold","no hold. Think of walking \"--\" horizontal line. This can be danced in place of Closed Basic Movements.","LF Alternative Basic Movement may end in Open PP","Man turning 1/8 L and Lady 1/8 R on 3. Likewise","RF Alternative Basic may end in Open CPP.","Leader","2: LF closes to RF","This is LF Alternative Basic Movement.","3: Transfer weight on RF","4 1: LF to side","2: RF closes to LF","This is RF Alternative Basic Movement.","3: Transfer weight to LF","4 1: RF to side","Follower","2: RF closes to LF","This is LF Alternative Basic Movement. Lady could do normal basic action","allowing body to move back more (pushing LF","try not to think about pulling center or foot back)","allow R arm to extend.","Still need to have forward energy toward partner.","3: Transfer weight on LF","4 1: RF to side","This is RF Alternative Basic Movement.","3: Transfer weight to RF","4 1: LF to side","Note: Silver & Gold: may dance this figure as: (may start with the other foot). count 2: close LF to RF without weight but with pressure. slight hip action count 3: hold position with weight on RF. Footwork: flat. Slight hip action. count 4 1: then LF side. Man may dance LF Alternative Basic in place of first 3 steps of any figure commenced in Open Position or Fan position","while leading Lady to dance her normal first 3 steps of figure selected. When commenced in Fan position","step 3 will be very small to keep correct positon in relation to Lady. When Man dances a LF Alternative Basic from Open Position as precede to Natural Top","he turns slightly R on step 3. Lady will dance \"close fwd fwd\" (RF LF RF)"]',
                    'Silver & Gold: Turn 3/8 to L over 4-6 to get to Contact Position.
step 3: RF side and slightly fwd. Lady LF behind RF as Cuban Cross.
Note: One should feel a continuous figure 8 action all the time.
Closed Basic Movement may end with taking step 6 in Open CPP, Man turning 1/8 R, Lady 1/8 L, Man release R hand hold.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

