-- Figure: Closed Hip Twist (Rumba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Closed Hip Twist',
                    (SELECT id FROM dance_type WHERE name = 'Rumba'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Fan Position',
                    '["Alemana","Hand To Hand RSP","Natural Top","New York LSP","Opening Out To Right And Left","Progressive Walks Forward in RSP","Progressive Walks Forward in Right Shadow Position","Rope Spinning","Shoulder To Shoulder Left Side","Three Alemanas"]',
                    '["Alemana","Hockey Stick","Sliding Doors","Fencing","Three Alemanas","Basic Movements: Open","Open Hip Twist","Curl","Three Threes","New York LSP","Spot or Switch Turn To R","Underarm Turn To L","Reverse Top"]',
                    'Alternative Finishing Positions:
Open Position: Man turn 1/4 L over 5 & 6
Open CPP:
Man turn 1/8 L over 5 & 6, leading lady to overturn on 5, both taking 6 diag. fwd.
Lady turns an additional 1/8 L on 5 using loosely crossed spiral action.
Contact Position:
Man turn 1/2 L over 5 & 6 to end RF side and slightly fwd.
Lady 3/4 L over 5 & 6 to end LF behind RF as Cuban Cross.
Normal hold retained throughout.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

