-- Figure: Curl (Rumba)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Curl',
    (SELECT id FROM dance_type WHERE name = 'Rumba'),
    true,
    'LF',
    'LF',
    'RF',
    'RF',
    'Open Position',
    'Fan Position',
    '["Advanced Hip Twists","Aida","Basic Movements","Closed Hip Twist","Curl","Hockey Stick","Open Hip Twist","Progressive Walks Forward","Spiral","Spot or Switch Turn to L (Lady to R)"]',
    '["Alemana","Hockey Stick","Sliding Doors","Fencing","Three Alemanas","Basic Movements","Open Hip Twist","Curl","Three Threes","New York LSP","Spot or Switch Turn to R (Lady to L)","Underarm Turn to L","Reverse Top"]',
    'At "1", still need to settle into R hip. 2: LF fwd Fan finish. Settle hip. 3: RF fwd and slightly across, then turn to end RF back. RF forward, slightly cross feet, upper thighs tight, sharp left turn. Push LF after turn. 4 1: LF back in Fan Position. For Fan finish, L hip to side, (do not rotate L to open up), keep thighs very tightly closed. Then, at "&", rotate L hip to draw RF in sharply, then twist hip to R into next figure.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

