-- Figure: Hand To Hand RSP (Rumba)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Hand To Hand RSP',
    (SELECT id FROM dance_type WHERE name = 'Rumba'),
    true,
    'LF',
    'LF',
    'RF',
    'RF',
    'Closed Position',
    'Open Position',
    '["Alemana","Basic Movements: Closed","Cuban Rocks RF","Fencing","Hand To Hand LSP","New York RSP","Progressive Walks Forward in LSP","Rope Spinning","Shoulder To Shoulder Right Side","Spot or Switch Turn to L (Lady to R)","Syncopated Cuban Rock LF","Three Alemanas","Underarm Turn To R"]',
    '["Basic Movements: Open (4-6)","Basic Movements: Closed (4-6)","New York RSP","Spot or Switch Turn to L (Lady to R)","Underarm Turn To R","Hand To Hand LSP","Side Step To Left commenced with RF","Side Step To Right commenced with RF","Cuban Rocks RF","Fan (4-6","lady in line on 4)","Closed Hip Twist (4-6","leading lady with R hand to turn R","then changing to L to R hand hold on 5)","Aida","Progressive Walks Forward in RSP (no turn on 2&3)","Spiral (Spiral after Hand to Hand to RSP- ending with Man close RF to LF and lead Lady to turn L into her spiral action on 3 to continue with 4-6 of Spiral)","Syncopated Cuban Rocks RF"]',
    'Hand To Hand RSP: may end in Open PP (1/8 over 2 & 3). RSP could be retained, making no turn over 2 &3 and taking step 3 fwd to follow with Progressive Walks Forward. More advanced: step 3 may be taken fwd in line with RF, then turn 1/2 to R to end LF back in LSP having release R to L hand hold and taken L to R hand hold. (Lady opposite.) Alternative hold: Can start with Normal hold. Man allow R hand to slide further around Lady''s back on step 1, releasing hold with L hand. Lady slide L hand naturally across Man''s shoulder. When following with Hand To Hand LSP, Man places L hand on Lady''s back, releasing R hand hold at end of step 3, while Lady rests R hand lightly across Man''s L shoulder. Man''s hand on Lady''s back is just below her shoulder blade.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

