-- Figure: New York (to LSP or RSP) Check from OCPP or OPP (Rumba)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'New York (to LSP or RSP) Check from OCPP or OPP',
    (SELECT id FROM dance_type WHERE name = 'Rumba'),
    true,
    'LF',
    'LF',
    'RF',
    'LF',
    'Open CPP',
    'Open CPP',
    NULL,
    NULL,
    'Note: RSP may be achieved after New York LSP by turning 1/8 more between step 3 of New York LSP and 1 of the next figure, to follow with Progressive Walks Forward. New York LSP may also be danced from Progressive Walks Forward in LSP (no turn on step 1 of New York LSP). Lady: break at wrist (think of showing off your ring), circle one round, ending downward. Hand at eye level. Advanced technique: Hip turns 1/8 extra than feet, frame (upper body) turn as much as possible to L (isolated from hip). Spine stays at same place as in basic technique. Do not break shoulder joint, arm is in same plane as body, if body can twist more, arm is more back. During the turn, arm line slowly going up, ideally ending with L hand behind head, arm sloped up. Basic technique: upper body flat forward, arm to the side. During the turn, arm line slowly going up, ideally ending with L hand behind head, arm sloped up. Keep center facing forward, then rotate upper body around spine to left, L hand/arm is "connected" with upper frame, don''t use shoulder joint as turning point for arm. "&": Get spine on to the foot with check action to change direction. R arm, the one connected with partner, do not push it forward, keep it tucked to side of body. Basic technique: upper body flat forward, arm to the side. Advanced technique: Hip turns 1/8 extra than feet, frame (upper body) turn as much as possible to L (isolated from hip). Spine stays at same place as in basic technique. Do not break shoulder joint, arm is in same plane as body, if body can twist more, arm is more back. During the turn, arm line slowly going up, ideally ending with L hand behind head, arm sloped up.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'New York (to LSP or RSP) Check from OCPP or OPP' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Rumba'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'New York (to LSP or RSP) Check from OCPP or OPP' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Rumba'));

