-- Figure: Rope Spinning (Rumba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Rope Spinning',
                    (SELECT id FROM dance_type WHERE name = 'Rumba'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Open Position',
                    'Closed Position',
                    '["Alemena","Continuous Hip Twists","Hand To Hand LSP","Natural Top","Rope Spinning","Three Alemanas"]',
                    '["Hand To Hand RSP","Basic Movements: Closed","Basic Movements: Open","Fan","Opening Out To Right And Left","Side Step To Left","Side Step To Right","Cuban Rock LF","Syncopated Cuban Rock LF","New York LSP","Spot or Switch Turn To R","Underarm Turn To L","Natural Opening Out Movement","Closed Hip Twist","Spiral","Rope Spinning","Advanced Hip Twists","Continuous Hip Twists","Circular Hip Twists","Progressive Walks Forward in Right Shadow Position"]',
                    'Alternative finishing positions:
Man and Lady end to side
Man and lady end diagonally fwd in Open CPP
Man 1/8 R on step 6.
Lady 7/8 to R over step 1 to 6.
Lady end fwd toward Man''s R side
Man turns body slightly R on step 6 to lead Lady towards his R side.
Lady LF fwd in line with RF.
Man and Lady fwd towards partner''s R side
Man RF fwd in line with LF towards Lady''s R side.
Lady LF fwd in line with RF
R Shadow Position
Man RF fwd in line with LF towards Lady''s R side, and continues to turn her R.
Lady ends LF back having made 1/2 turn R on LF during preceding beat.
Adopt R shadow Hold.'
                )
