-- Figure: Sliding Doors (Rumba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Sliding Doors',
                    (SELECT id FROM dance_type WHERE name = 'Rumba'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'LF',
                    'Fan Position',
                    'RSP',
                    '["Advanced Hip Twists","Alemana","Closed Hip Twist","Curl","Fan","Open Hip Twist","Opening Out From Reverse Top","Rope Spinning","Spiral","Three Alemanas","Three Threes"]',
                    '["Progressive Walks Forward","Spiral"]',
                    'Note:
Alternative hold:
Man:
- keep L hand below chest level, taking R to R hand hold at end of 3, releasing hold with L hand.
- Then, lead Lady with R hand to pass in front of him to R side, releasing hold at end of 5, allowing R hand to trail along Lady''s R arm until it reaches her R shoulder blade o step 6.
- Then, take Lady''s L hand into his L hand. (R shadow position, hold 1) Retain this hold for steps 7 to 12.
When following with Lady''s Spiral, man lead Lady into her spiral turn by lowering L hand, then immediately gaining normal Fan or Open Position hold at end of last step.
When following with Progressive Walks Forward, retain R Shadow hold.
Variation w/ Lady''s R turn to hip twist position:
- 2: Cucaracha LF to side, whole foot
- 3: weight to RF, LF push floor, L heel lift, L hip up, hip diagonally to R and then rotate to R, collect LF near R ankle and then step forward to Man''s R side on 4.
- 4: LF forward to Man''s R side. L arm to side, R hand on Man''s chest.
Preceding Figures
Advanced Hip Twists
Alemana
Closed Hip Twist
Curl
Fan
Open Hip Twist
Opening Out From Reverse Top
Rope Spinning
Spiral
Three Alemanas
Three Threes
Following Figures
Progressive Walks Forward (in Right Shadow Position, hold 2 or 3 (Kiki Walks))
Spiral'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

