-- Figure: Natural Twist Turn (Foxtrot)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Natural Twist Turn',
                    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'RF',
                    'Closed Position',
                    'Fan Position',
                    '["Closed Telemark","Hover Telemark","Three Step"]',
                    '["Three Step","Reverse Turn","Change Of Direction","Closed Telemark","Open Telemark and Feather Ending","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Hover Telemark","Reverse Wave","Top Spin","Outside Swivel (check back after step 3 of Feather Step)","Fallaway Reverse and Slip Pivot","Bounce Fallaway with Weave Ending","Natural Weave","Closed Impetus and Feather Finish","Open Impetus"]',
                    'Lady optional styling: head could change to R during Weave.
Natural Twist Turn with Hover Feather Ending described with specific sway and CBM details.
Natural Twist Turn with Natural Weave Ending includes continuation with 3-8 of Natural Weave and finish BDW.
Natural Twist Turn with Closed Impetus And Feather Finish Ending ends with feather finish after RF brush.
Natural Twist Turn with Open Impetus Ending uses Open Impetus movement and feather finish.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

