-- Figure: OpenTelemark and Feather Ending (Foxtrot)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'OpenTelemark and Feather Ending',
                    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'RF',
                    'Closed Position',
                    'Promenade Position',
                    '["Closed Impetus and Feather Finish","Fallaway Reverse and Slip Pivot","Feather Step","Hover Cross","Hover Feather","Natural Hover Telemark","Natural Telemark","Natural Twist Turn","Natural Zig-Zag from PP","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Top Spin"]',
                    '["Three Step","Change Of Direction","Basic Weave (1-4 Reverse Turn to end BDW","check","and Basic Weave)","Reverse Turn (1-4 Reverse Turn to end BLOD near corner","check and Basic Weave turning 1/8","1/8","3/4; or 1/4","1/8","3/4; to end DW of new LOD)","Hover Telemark","Reverse Wave","Top Spin (check back after step 6)","Outside Swivel (check back after step 6)","Fallaway Reverse and Slip Pivot (at corner)"]',
                    'When leading to PP ending, Man left his LF there (like in spiral turn), there is no brush, LF then steps out in step 3 to PP.
Body turn less to PP. Keep body facing Lady.
It''s different to do feather finish from PP. Lady really has to use this step 4 (S) and next step 5 (Q) to move a lot of space to keep up with Man.
Swing R hip forward, then allow feet to turn under the body.
Body never feels travel side ways. Body feels like traveling forward.
R side stretch diagonally.
Keep arms forward in front of body.
LF back in CBMP | Backing DW | TH | 1/8 between 5-6, body turns less | Sway(L) | up, NFR Lower e/o6'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

