-- Figure: Cucarachas (Rumba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Cucarachas',
                    (SELECT id FROM dance_type WHERE name = 'Rumba'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Closed Position',
                    '["Aida","Cucarachas","Fencing"]',
                    '["Spot or Switch Turn To R (Lady to L)","Basic Movements: Open","Basic Movements: Closed","Aida"]',
                    'Feet relative direction to each other: side, side and slightly fwd or back, fwd or diagonally fwd, back or diagonally back.
Gold level: A Press Line may be used by Man when dancing a fwd Cucaracha by allowing RF to swivel slightly to R as he steps a fwd LF in line with RF, on ball of foot with heel raised.
L knee is flexed, R leg straight and RF flat.
There is no hip movement.
The Press Line may be used on 1 of Advanced, Continuous and Circular Hip Twists.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
