-- Figure: Rumba Fencing (Rumba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Rumba Fencing',
                    (SELECT id FROM dance_type WHERE name = 'Rumba'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Fan Position',
                    'Closed Position',
                    '["Advanced Hip Twists","Closed Hip Twist","Curl","Fan","Open Hip Twist","Opening Out From Reverse Top","Spiral","Three Threes"]',
                    '["New York LSP","Spot or Switch Turn To R (Lady to L)","Underarm Turn To L","Basic Movements: Closed","Basic Movements: Open","Cucarachas: LF","Side Step To Left commenced with LF","Fan","Hand To Hand RSP","Side Step To Right commenced with LF","Cuban Rock LF"]',
                    'Notes on endings:
Man and Lady''s Solo Spin
On step 6, at end of count 4, continue turning a further 7/8 (Lady to L and Man to R), release L to R hand hold. End facing partner, both feet closed. Man LF without weight. Lady with RF without weight, but with pressure into the ball of foot. Take required hold.
Lady''s Under Arm Spin to L
On step 6, at end of count 4, Lady spins a full turn to L under Man''s raise arm, end with RF closed to LF without weight, with pressure into the ball of RF.
Man''s Solo spin to L
Lady does not turn, Man does his full spin to his R, end facing partner.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

