-- Figure: Natural Opening Out Movement (Rumba)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Natural Opening Out Movement',
    (SELECT id FROM dance_type WHERE name = 'Rumba'),
    true,
    'LF',
    'RF',
    'RF',
    'RF',
    'Closed Position',
    'Closed Position',
    '["Alemana","Natural Top","Rope Spinning","Three Alemanas"]',
    '["Fan","Basic Movements: Closed","Basic Movements: Open","Natural Opening Out Movement","Closed Hip Twist","Spiral (1/4 R on 1)"]',
    'Note: Man is dancing a LF Cucaracha and RF Cucaracha. Turn on step 1 and 4 are made at end of previous beat. An Extended Forward Walk may be used on steps 3 & 6. Variations (Silver & Gold): Man may place R hand on Lady''s back on 6, release L hand hold. Lady: place L hand on Man''s R shoulder and turn 1/4 R into step 1 of following figure to 90 degree. Normal hold is regained on step 3 of following figure. Man may lead lady fwd towards his R side on last step of preceding figure and then turn 1/4 R on RF keeping his feet together, at the same time leading Lady to turn R. Lady LF fwd in line with RF towards Man''s R side, then turn 1/2 R on LF to end LF back at a 90 degree angle to Man. No turn on step 1 of the following Opening Out Movement.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

