-- Figure: Shoulder To Shoulder (Rumba)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Shoulder To Shoulder',
                    (SELECT id FROM dance_type WHERE name = 'Rumba'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'RF',
                    'Closed Position',
                    'Closed Position',
                    '["Hockey Stick","Basic Movements: Closed","Underarm Turn To R","Spot or Switch Turn to L (Lady to R)","Side Step To Right commenced with RF","Cuban Rocks RF","Fan","Closed Hip Twist","Syncopated Cuban Rocks RF","New York RSP"]',
                    '["Shoulder To Shoulder Right Side","Basic Movements: Open (4-6","when ending facing partner)","Basic Movements: Closed (4-6","when ending facing partner)","Spot or Switch Turn To R (Lady to L) (when ending facing partner; or when ending Open CPP)","Underarm Turn To L (when ending facing partner; or when ending Open CPP)","Hand To Hand RSP (when ending facing partner)","Side Step To Left commenced with LF (when ending facing partner)","Side Step To Right commenced with LF (when ending facing partner)","Cuban Rock LF (when ending facing partner)","Fan (when ending facing partner)","Syncopated Cuban Rock LF (when ending facing partner)","New York LSP (when ending Open CPP)"]',
                    'Shoulder To Shoulder Left side:
Following Hockey Stick (Man move slightly towards Lady''s L side on last step), Shoulder to Shoulder may be danced with L to R or double hand hold (end in Open PP, then followed by Spot or Switch turn to L)
Man keeps the L hand higher than usual to prevent Lady moving too far back on last step of the Hockey Stick, although the couple will be further apart than when dancing the figure in Closed Position.
When danced this way, it can end in Open PP, Lady no turn.
Similarly for Shoulder To Shoulder Right side.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

