-- Figure: Closed Promenade (Tango)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Closed Promenade',
                    (SELECT id FROM dance_type WHERE name = 'Tango'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Closed Position',
                    '["Basic Reverse Turn","Chase","Contra Check","Fallaway Four Step","Fallaway Promenade","Five Step","Four Step","Natural Promenade Turn","Natural Twist Turn","Open Finish","Open Promenade","Open Reverse Turn","Lady In Line","Open Reverse Turn","Lady Outside","Oversway","Progressive Link","Progressive Side Step Reverse Turn"]',
                    '["Walk (LF)","Progressive Side Step","Progressive Link","Back Corte","LF Rock","Open Reverse Turn","Lady Outside (when preceding figure ended DC)","Open Reverse Turn","Lady In Line (when preceding figure ended DC)","Progressive Side Step Reverse Turn (when preceding figure ended DC)","Reverse Outside Swivel (when preceding figure ended DC)","Basic Reverse Turn (when preceding figure ended DC)","Fallaway Reverse and Slip Pivot (when preceding figure ended DC; or normal)","Four Step","Outside Swivel","Four Step Change","Brush Tap","Fallaway Four Step","Oversway","Five Step","Contra Check"]',
                    'Note:
Man may turn square to the lady in step 3, to end backing DC. Footwork for man would then be IE BH and for the lady IE of foot.

The feeling is that Lady is dancing at Man''s right edge. Upper body is very much behind Man''s hip.
Stay connected with Man, keep R side fwd rotated to Man.
RF Toe in line with LF. "side" step is like a forward step. Move "with" the Man.
Head sharp flip to L, keep the volume between 2 heads, extended right away (do not close with Man and then extend in 2 steps). It''s very easy to get in front of Man during transition of steps. Be very aware to continue to stretch L during the steps. Head motion is generally in sync with hip movement.
Keep frame solid: don''t lose R arm, R arm fwd to Man with tone, it doesn''t go back, or becomes "loose". keep R elbow out, not down.
This is the sharp, accent step. (compared to next step "LF closes to RF" is softer and smoother)
S: LF closes to RF slightly fwd | Backing DW | Whole foot
Do not slide foot. Left foot roll off and end on ball of front of LF, then lift and place LF close to RF (could have a very small gap), slightly forward.
Softer and smoother step, not the sharp accent.
Back to starting foot position.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

