-- Figure: Natural Promenade Turn (Tango)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Natural Promenade Turn',
                    (SELECT id FROM dance_type WHERE name = 'Tango'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'RF',
                    'Closed Position',
                    'Promenade Position',
                    '["Basic Reverse Turn","Chase","Contra Check","Fallaway Four Step","Fallaway Promenade","Five Step","Four Step","Natural Promenade Turn","Natural Twist Turn","Open Finish","Open Promenade","Open Reverse Turn","Lady In Line","Open Reverse Turn","Lady Outside","Oversway","Progressive Link","Progressive Side Step Reverse Turn"]',
                    '["Closed Promenade","Open Promenade","Natural Promenade Turn","Promenade Link","Back Open Promenade","Fallaway Promenade","Rock Turn (2-7)"]',
                    'Amount of Turn: 3/4 to right.
If the Promenade Turn is danced along the side of the room 3/4 is still made. The following Promenade would be taken to the center, or a slight body turn to R may be used as the LF is place to side of RF to enable the following Promenade to be taken DC.
When this Natural Promenade Turn is followed by steps 2-7 Rock Turn, skip step 4 (placing RF to side), it is more flat and rotational (compared to Twist Turn).
Natural Promenade Turn follows the Fallaway Promenade.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

