-- Figure: Open Finish (Tango)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Open Finish',
                    (SELECT id FROM dance_type WHERE name = 'Tango'),
                    true,
                    'RF',
                    'LF',
                    'LF',
                    'LF',
                    'Promenade Position',
                    'Open Finish',
                    '["LF Rock","Walk (LF)","Progressive Side Step","Progressive Link","Open Reverse Turn","Lady Outside (when preceding figure ends DC)","Open Reverse Turn","Lady In Line (when preceding figure ends DC)","Progressive Side Step Reverse Turn (when preceding figure ends DC)","Reverse Outside Swivel (when preceding figure ends DC; or normal)","Basic Reverse Turn (when preceding figure ends DC)","Fallaway Reverse and Slip Pivot (when preceding figure ends DC; or normal)","Four Step","Four Step Change","Brush Tap","Fallaway Four Step","Oversway","Five Step","Back Corte (step 1 of Back Corte in CBMP with Lady OP)","LF Rock (LF Rock in CBMP with Lady OP","no turn or up to 1/4 to R)","Outside Swivel","Closed Promenade (after Open Finish","place LF to side without weight leading Lady to turn to PP","count &","then proceed with the Promenade figure)","Open Promenade (after Open Finish","place LF to side without weight leading Lady to turn to PP","count &","then proceed with the Promenade figure)","Natural Promenade Turn (after Open Finish","place LF to side without weight leading Lady to turn to PP","count &","then proceed with the Promenade figure)","Promenade Link (after Open Finish","place LF to side without weight leading Lady to turn to PP","count &","then proceed with the Promenade figure)","Back Open Promenade (after Open Finish","place LF to side without weight leading Lady to turn to PP","count &","then proceed with the Promenade figure)","Fallaway Promenade (after Open Finish","place LF to side without weight leading Lady to turn to PP","count &","then proceed with the Promenade figure)"]',
                    NULL,
                    'Technique Notes
Other alignments and directions may be used.
Amount of turn: slightly less turn to L will be made on a figure when changing a Closed Finish to Open Finish. Although normal turn will be made when following with a curve or turn to L, e.g. Walk on LF, or Outside Swivel turning L from Open Finish (method 2).
Follows can be moving forward, back or to side. When stepping forward from and Open Finish, step 1 will not be taken in CBMP.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

