-- Figure: Progressive Link (Tango)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Progressive Link',
    (SELECT id FROM dance_type WHERE name = 'Tango'),
    true,
    'LF',
    'RF',
    'RF',
    'LF',
    'Closed Position',
    'Promenade Position',
    '["Back Corte","Basic Reverse Turn","Brush Tap","Chase","Closed Finish","Closed Promenade","Fallaway Reverse and Slip Pivot","Four Step Change","Open Finish","Open Promenade","Open Reverse Turn","Lady In Line","Open Reverse Turn","Lady Outside","Outside Swivel","Progressive Side Step Reverse Turn","Promenade Link","Reverse Outside Swivel","Rock Turn","Walk"]',
    '["Closed Promenade","Open Promenade","Natural Twist Turn","Natural Promenade Turn","Promenade Link","Back Open Promenade","Fallaway Promenade","Chase"]',
    'Note: The figure has solid, sharp feeling, not soft. It is more of an "upward" action with body projecting upward. 90 body rotation in body seems to give the right look and impact. Promenade position: Lady''s L hip feels like rolled downward and backward, R hip fwd stretched, toward Man. Hip is level, Lady may feel R hip is higher. Hips has an diagonal angle to Man. L hip is "released". Upper body is closed more. Actions are in hips, nothing should affect top shoulder line, arm relaxed, no increased tension. Even when doing with full power, arms should not be involved. When moving out of PP, LF fwd, legs are moving, hips don''t change, L hip stays in "bent/release" position, don''t flatten out L hip when stepping LF fwd. As described above, the link starts in DW. But often, link is preceded by 2 walks which started DW. Walks naturally curve to left, so the Link will end up with Man''s feet facing LOD, Woman''s feet facing center., traveling DC.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

