-- Figure: Progressive Side Step (Tango)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Progressive Side Step',
                    (SELECT id FROM dance_type WHERE name = 'Tango'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'RF',
                    'Closed Position',
                    'Side Position',
                    '["Back Corte","Brush Tap","Closed Promenade","Fallaway Reverse and Slip Pivot","Four Step Change","Open Finish","Open Promenade","Outside Swivel","Promenade Link","Reverse Outside Swivel","Rock Turn","Walk"]',
                    '["Walk (LF)","Progressive Side Step","Progressive Link","Back Corte","LF Rock","Closed Promenade (at end of last step of preceding figure","using Open Finish","keep feet in place and turn Lady to PP","count &)","Open Promenade (at end of last step of preceding figure","using Open Finish","keep feet in place and turn Lady to PP","count &)","Natural Promenade Turn (at end of last step of preceding figure","using Open Finish","keep feet in place and turn Lady to PP","count &)","Promenade Link (at end of last step of preceding figure","using Open Finish","keep feet in place and turn Lady to PP","count &)","Back Open Promenade (at end of last step of preceding figure","using Open Finish","keep feet in place and turn Lady to PP","count &)","Fallaway Promenade (at end of last step of preceding figure","using Open Finish","keep feet in place and turn Lady to PP","count &)","Four Step","Outside Swivel","Four Step Change","Brush Tap","Fallaway Four Step","Five Step","Contra Check"]',
                    'A slight turn to left can be made, in which case there is slight CBM on 1 and 3
When there is turn and CBM, footwork changes accordingly to IE of BH (or outside edge of BH, as it applies).
Progressive side step is often used to handle traffic, not typically designed to be used in a routine.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

