                    'Double Reverse Spin',
                    (SELECT id FROM dance_type WHERE name = 'Waltz'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Closed Position',
                    '["Closed Change RF","Closed Wing","Fallaway Reverse And Slip Pivot","Hesitation Change","Reverse Pivot","Reverse Turn","Wing"]',
                    '["Drag Hesitation","Closed Change LF","Whisk","Double Reverse Spin","Reverse Turn","Closed Telemark","Open Telemark","Progressive Chasse To R","Contra Check","Fallaway Reverse And Slip Pivot"]',
                    'Advanced dancers often use the timing of 123& when the beat value would be 1, 1, 1/2, 1/2. Per coach: Timing: do 1 2 &3. Man''s early rise signals Lady should do heel turn. Lady does RF "back", L heel closes to R heel, turn, rise and "forward", then RF "out" to side (after turning) and "cross", stay on left.
Note: The Double Reverse Spin may be started DC, DW, or LOD. The amount of turn may vary between 3/4 and a whole turn.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
