-- Figure: Turning Lock to Right (WALTZ) (Waltz)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Turning Lock to Right (WALTZ)',
                    (SELECT id FROM dance_type WHERE name = 'Waltz'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'RF',
                    'Closed Position',
                    'Closed Position',
                    '["Closed Impetus","Natural Spin Turn","Outside Spin"]',
                    '["Wing","Weave From Promenade Position","Cross Hesitation","Natural Spin Turn","Natural Turn","Closed Wing","Chasse From Promenade Position","Left Whisk"]',
                    'Turning lock curves gently forward.
In Turning Lock, foot rise comes before body rise (rise on count 2 LF, or end of 1& on RF).
Last step of preceding Natural Spin Turn: Footwork for will be the normal TH for Man and Lady.
It may be shaped to the man''s left, leading the lady to turn her head right.
The Turning Lock may end in PP, see Outside Change ended in PP.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Turning Lock to Right (WALTZ)' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));
