-- Figure: CurvedFeather to Back Feather (SLOW_FOXTROT) (Foxtrot)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'CurvedFeather to Back Feather (SLOW_FOXTROT)',
    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
    true,
    'RF',
    'LF',
    'LF',
    'LF',
    'Closed Position',
    'Back Feather Position',
    '["Change Of Direction","Closed Telemark","Hover Telemark","Hover Telemark to PP","Natural Turn","Open Impetus","Outside Swivel","Reverse Wave","Three Step"]',
    '["Closed Impetus and Feather Finish","Basic Weave (At corner)","Open Impetus (After steps 1-3)"]',
    'The figure begins in closed position and progresses through a series of steps with specific sway, CBM and rise patterns. Leader starts with RF forward, followed by LF diagonal forward, RF forward in CBMP, LF back in CBMP, then continues with RF back, LF back, and ends with RF back. Follower mirrors with LF back, RF back, LF back, RF forward in CBMP, LF forward, RF forward in CBMP, and finishes with LF forward. The ending position is typically a Back Feather Position with possible continuation to Feather Finish SQQ. Sway, CBM and rise are emphasized throughout. The figure is at Gold level. Notes include alignment details, amount of turn, and specific footwork instructions.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'CurvedFeather to Back Feather (SLOW_FOXTROT)' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'CurvedFeather to Back Feather (SLOW_FOXTROT)' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));

