-- Figure: Natural Twist Turn (Foxtrot)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Natural Twist Turn',
    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
    true,
    'RF',
    'RF',
    'LF',
    'LF',
    'Closed Position',
    'Hover Feather',
    '["Closed Telemark","Hover Telemark","Three Step"]',
    '["Three Step","Reverse Turn","Change Of Direction","Closed Telemark","Open Telemark and Feather Ending","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Hover Telemark","Reverse Wave","Top Spin","Outside Swivel","Fallaway Reverse and Slip Pivot","Bounce Fallaway with Weave Ending","Natural Weave","Closed Impetus and Feather Finish","Open Impetus"]',
    'The figure is presented with several possible endings: Hover Feather Ending, Natural Weave Ending, Closed Impetus and Feather Finish Ending, and Open Impetus Ending. No upward swing occurs on the first three steps. Timing, sway, CBM, and foot placements are detailed for both leader and follower. Styling options include head direction changes and weight distribution. The figure includes a series of steps with specific alignments (Facing LOD, Backing DC, etc.) and amounts of turn (continue to turn R, etc.).'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Natural Twist Turn' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Natural Twist Turn' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));

