-- Figure: Natural Zig-Zag from PP (Foxtrot)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Natural Zig-Zag from PP',
                    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
                    true,
                    'RF',
                    'LF',
                    'LF',
                    'RF',
                    'Promenade Position',
                    'Backing DW',
                    '["Hover Telemark","Hover Telemark to PP","Open Impetus","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Outside Swivel"]',
                    '["Three Step","Change Of Direction","Hover Telemark","Reverse Wave (normal; or if ended DC)","Reverse Turn (if ended DC)","Closed Telemark (if ended DC)","Open Telemark and Feather Ending (if ended DC)","Fallaway Reverse and Slip Pivot (if ended DC)","Bounce Fallaway with Weave Ending (if ended DC)","Open Telemark","Natural Turn","Outside Swivel and Feather Ending"]',
                    'Do not drop R side, ribs to Man.
Man is doing swiveling through his feet. Lady changes from PP to Man''s L side and then R side, OP.
Q: RF diag fwd, preparing to step OP on L side | Facing DC | T | 1/8 between 1-2 | Sway(S) | Up 
Use glute, pick up the hip fwd, Swing hip fwd and up.
Take head to L and keep head head through the rest of steps.
Do not try making connection by arching the back.
Have loose contact with Man, sliding from one side to another.
Q: LF fwd in CBMP, OP on L side | Facing DC | T | Start to turn L | Sway(S) | CBM | Up
Different alignment for Man and Lady on steps 3-4.
Q: RF to side | Backing Wall | TH | 1/8 between 3-4, body turns less | Sway(L) | Up
Use L glute to push. Swing R hip. Feather finish.
Q: LF back in CBMP | Backing DW | TH | - | Sway(L) | Up. Lower e/o 5
S: RF back | Backing DW | T | - | Sway(S) | CBM'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Natural Zig-Zag from PP' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Natural Zig-Zag from PP' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));

