-- Figure: Top Spin (Foxtrot)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Top Spin',
                    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'RF',
                    'Closed Position',
                    'Closed Position',
                    '["Basic Weave","Bounce Fallaway with Weave Ending","Closed Impetus and Feather Finish","Feather Step","Hover Feather","Natural Twist Turn","Natural Weave","Open Telemark and Feather Ending","Reverse Turn"]',
                    '["Reverse Turn","Closed Telemark","Open Telemark and Feather Ending","Reverse Wave","Three Step","Change Of Direction","Hover Telemark","Fallaway Reverse and Slip Pivot","Bounce Fallaway with Weave Ending"]',
                    'On step 1 the footwork of TH may be used. This will often result in a softer and more flowing movement. When this footwork is used the rise will be "Up NFR" on step 2. On step 6 of the preceding Reverse Turn with Feather Ending, Man''s body will be facing DW and the Lady will be backing DW.
Silver and Gold: Closed Impetus and Feather Finish may be danced turning 1/2 on step 1-3 to back against LOD and 3/8 on Feather Finish to face DC against LOD. Continue with Top Spin to face DW.
Open Telemark, Natural Turn to Outside Swivel may be danced, turning only 1/8 to R for Man, 3/8 for Lady on step 7 to follow with Feather Ending DC against LOD into Top Spin.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

