-- Figure: Open Promenade (Tango)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Open Promenade',
                    (SELECT id FROM dance_type WHERE name = 'Tango'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Promenade Position',
                    'Open Finish',
                    '["Basic Reverse Turn","Chase","Contra Check","Fallaway Four Step","Fallaway Promenade","Five Step","Four Step","Natural Promenade Turn","Natural Twist Turn","Open Finish","Open Promenade","Open Reverse Turn","Lady In Line","Open Reverse Turn","Lady Outside","Oversway","Progressive Link","Progressive Side Step Reverse Turn"]',
                    '["Walk (LF)","Progressive Side Step","Progressive Link","Open Reverse Turn","Lady Outside","Open Reverse Turn","Lady In Line","Progressive Side Step Reverse Turn","Reverse Outside Swivel","Basic Reverse Turn","Fallaway Reverse and Slip Pivot","Four Step","Four Step Change","Brush Tap","Fallaway Four Step","Oversway","Five Step","Back Corte","LF Rock","Outside Swivel","Closed Promenade","Open Promenade","Natural Promenade Turn","Promenade Link","Back Open Promenade","Fallaway Promenade"]',
                    'Note:
Man may turn square to the lady in step 3, to end backing DC. Footwork for man would then be IE BH and for the lady IE of foot.
Preceding Figures
Basic Reverse Turn
Chase
Contra Check
Fallaway Four Step
Fallaway Promenade
Five Step
Four Step
Natural Promenade Turn
Natural Twist Turn
Open Finish
Open Promenade
Open Reverse Turn, Lady In Line
Open Reverse Turn, Lady Outside
Oversway
Progressive Link
Progressive Side Step Reverse Turn
Following Figures
Walk (LF)
Progressive Side Step
Progressive Link
Open Reverse Turn, Lady Outside (when preceding figure ended DC)
Open Reverse Turn, Lady In Line (when preceding figure ended DC)
Progressive Side Step Reverse Turn (when preceding figure ended DC)
Reverse Outside Swivel (when preceding figure ended DC; or normal)
Basic Reverse Turn (when preceding figure ended DC)
Fallaway Reverse and Slip Pivot (when preceding figure ended DC; or normal)
Four Step
Four Step Change
Brush Tap
Fallaway Four Step
Oversway
Five Step
Back Corte (step 1 in CBMP with Lady OP using CBM on 1 and 2)
LF Rock (LF Rock in CBMP with Lady OP, no turn or up to 1/4 to R)
Outside Swivel
Closed Promenade (having placed LF to side without weight, leading Lady to to PP, count &)
Open Promenade (having placed LF to side without weight, leading Lady to to PP, count &)
Natural Promenade Turn (having placed LF to side without weight, leading Lady to to PP, count &)
Promenade Link (having placed LF to side without weight, leading Lady to to PP, count &)
Back Open Promenade (having placed LF to side without weight, leading Lady to to PP, count &)
Fallaway Promenade (having placed LF to side without weight, leading Lady to to PP, count &)'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

