-- Figure: Weave in Waltz Time (Waltz)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Weave in Waltz Time',
                    (SELECT id FROM dance_type WHERE name = 'Waltz'),
                    true,
                    'RF',
                    'LF',
                    'LF',
                    'LF',
                    'Closed Position',
                    'Promenade Position',
                    '["Natural Spin Turn","Outside Spin","Reverse Turn"]',
                    '["Natural Spin Turn","Natural Turn","Hesitation Change","Left Whisk","Wing","Chasse from Promenade Position","Closed Wing","Cross Hesitation"]',
                    'Variation: this step can finish in Promenade position going DW
step 3: ending moving down LOD
step 4: same, LOD
step 5: Man back step, Lady: fwd; CBM
step 6: lady: RF forward DW (after collecting/brushing). then collect LF, ending in promenade position.
This step is usually used in corners. Not very good to use along LOD to stop movement.
When Reverse Turn precedes this step, it''s better to commence 3 steps Reverse Turn facing LOD.
More advanced version: use ball of foot to whole foot on step 1.
Soft knee on this step.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

