INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    '1ddad4c0-96d2-376b-ab86-bf67f433b1bb',
    '2cafb1ab-a2d6-3adc-a1de-cf7398918d5a',
    'RF back in CBMP | BDW, feet almost BLOD | T | Body turn to L | -- | CBM | Down with knees slightly flexed',
    1
