-- Figure: DoubleReverse Spin (Waltz)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'DoubleReverse Spin',
    (SELECT id FROM dance_type WHERE name = 'Waltz'),
    true,
    'LF',
    'RF',
    'RF',
    'LF',
    'Closed Position',
    'Backing DW',
    '["Closed Change RF","Closed Wing","Double Reverse Spin","Fallaway Reverse And Slip Pivot","Hesitation Change","Reverse Pivot","Reverse Turn","Wing"]',
    '["Drag Hesitation","Closed Change LF","Whisk","Reverse Turn","Closed Telemark","Open Telemark","Progressive Chasse To R"]',
    'Advanced dancers often use the timing of 123& when the beat value would be 1, 1, 1/2, 1/2. Per coach: Timing: do 1 2 &3. Man''s early rise signals Lady should do heel turn. Lady does RF "back", L heel closes to R heel, turn, rise and "forward", then RF "out" to side (after turning) and "cross", stay on left. Note: The Double Reverse Spin may be started DC, DW, or LOD. The amount of turn may vary between 3/4 and a whole turn.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'DoubleReverse Spin' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'DoubleReverse Spin' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));

