INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    'c7f50163-8324-3736-8a2b-3dae93f48b55',
    '5d1a5d07-a848-3709-aa0e-17ad2f94226f',
    'To produce big shape: Take step LF back (along original travel direction, don''t go around Man), move weight back to LF (this is a step, otherwise you''ll block Man), collect RF (crossed in front of LF, w/o weight).',
    1
);
INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    '4cf5bd4d-632f-358b-9271-0de5e4d4bb75',
    '5d1a5d07-a848-3709-aa0e-17ad2f94226f',
    'Butt and hip fwd to Man, don''t turn out of Man. Hips stop turning, but body can continue to turn more to shape/sway without changing base.',
    2
);
INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    '6867e90a-586d-3231-a6a0-f6cd36664136',
    '5d1a5d07-a848-3709-aa0e-17ad2f94226f',
    'Contra within own body. Both L and R rib cage and hips fwd to Man and shape to L (w/o turning hips more), R side of body is longer (very stretched). Don''t "sit" bottom down, heavy. Pick up center and bottom. Really pick up L side ribs to Man while rotating body to L and extending head to L.',
    3
);
INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    '42946531-9ac4-3091-aff8-e55ebb7ebfcb',
    '5d1a5d07-a848-3709-aa0e-17ad2f94226f',
    'Head turns well to left and extend (without body peeling from Man) to finish the extension. Breathe out to extend head even more.',
    4
);
INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    '18da3ab8-5d46-38e6-86c8-fa67b929d75a',
    '5d1a5d07-a848-3709-aa0e-17ad2f94226f',
    'Keep arm/elbow forward, extend the arm fwd to Man (check R elbow angle), give it to Man. Don''t break shoulder or peel away shoulder.',
    5
);

-- Figure: Open Impetus and Cross Hesitation (Waltz)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Open Impetus and Cross Hesitation',
    (SELECT id FROM dance_type WHERE name = 'Waltz'),
    true,
    'LF',
    'LF',
    'RF',
    'RF',
    'Closed Position',
    'PP',
    '["Back Lock","Drag Hesitation","Left Whisk","Natural Turn","Progressive Chasse To R","Reverse Corte"]',
    '["Chasse From Promenade Position","Weave From Promenade Position","Cross Hesitation","Wing","Left Whisk"]',
    'Different from leading Wing, in which, Man allows upper body to do extra rotation to allow Lady to pass from one side of body to another. In this Cross Hesitation, Man''s arms remain on his right side, you want Lady to stay in your right front. Connecting Figures for Cross Hesitation See Open Telemark and Cross Hesitation.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

