INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Cross Swivel',
    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
    true,
    'LF',
    'RF',
    'RF',
    'LF',
    'Closed Position',
    'Closed Position',
    '["Double Reverse Spin","Heel Pivot (Quarter Turn To Left)","Reverse Pivot"]',
    '["Tipple Chasse To Right","Running Finish","Fish Tail","Tipsy To R (After LF back with Lady OP","TH","S","into Tipsy to R)"]',
    'Alternative styling: RF to side, knees inward; LF to side, knee inward; give arms to R; keep left side lifted; give R side to Man; stay connected; turn head to R; rise feeling before next S lower to normal; not sinking down.'
)
