-- Figure: Four QuickRun (Quickstep)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Four QuickRun',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'LF',
                    'Closed Position',
                    'Closed Position',
                    '["Chasse Reverse Turn","Closed Impetus","Closed Telemark","Fish Tail","Forward Lock","Hover Corte","Natural Spin Turn","Progressive Chasse","Progressive Chasse To Right","Quarter Turn to Right","Quick Open Reverse","Running Finish","Six Quick Run","Tipple Chasse To Right","V6"]',
                    '["Running Right Turn","Natural Turn And Back Lock","Natural Pivot Turn","Natural Spin Turn","Natural Turn With Hesitation","Natural Turn","Quarter Turn to Right","Forward Lock","V6 (at corner","LF back with Lady OP","TH","S","into 2-12 V6)","Fish Tail","Tipsy To L (into 2-5 Back Lock down LOD)","Six Quick Run (LF back with Lady OP","TH","S","into Six Quick Run)"]',
                    'Don''t be back-weighted, avoid being steppy, keep smooth motion.
Keep left side strongly to the Man all through the steps.
Do not think about rotating upper body to R, which can take spine off standing leg.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

