-- Figure: Hover Corte (Quickstep)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Hover Corte',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'RF',
                    'LF',
                    'LF',
                    'RF',
                    'Closed Position',
                    'Closed Position',
                    '["Chasse Reverse Turn","Closed Impetus","Natural Spin Turn","Quarter Turn to Right","Quick Open Reverse"]',
                    '["Tipple Chasse To Right","Tipsy To R","Running Finish","Tipsy To L","Four Quick Run (At corner)","V6 (At corner","2-12 of V6)","Six Quick Run (At corner)"]',
                    'Maintain alignment and rise on appropriate beats; avoid excessive sway; keep shoulders, hips, and legs lined; use CBM; lead with right ribs; extension through arm; head can start left then open to right then close.
Preserve shape from lower abdomen up; do not just bend from waist.
Connection lower (hips, upper legs) pressing with partner; allow extension.
Be aware of delayed reaction; man takes head to foot then develops shape.
When giving right ribs/side, tone extends to right arm and hand to man forward.
Begin head can be kept left; later open to right then close and turn left when shaping.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

