-- Figure: Natural SpinTurn (Quickstep)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Natural SpinTurn',
    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
    true,
    'RF',
    'RF',
    'LF',
    'LF',
    'Closed Position',
    'Closed Position',
    '["Closed Telemark","Cross Chasse","Fish Tail","Forward Lock Step","Four Quick Run","Heel Pivot (Quarter Turn To Left)","Natural Pivot Turn","Natural Turn","Progressive Chasse","Running Finish","Running Right Turn","Tipple Chasse To Right","V6","Zig-Zag","Back Lock And Running Finish"]',
    '["Progressive Chasse","Reverse Pivot","Heel Pivot (Quarter Turn To Left)","Four Quick Run","V6 (2-12","heel should lower on previous step)","Six Quick Run (heel should lower on previous step)","Hover Corte"]',
    'When connecting with V6 (QQS lock step), the footwork for this count becomes THT. Preceding Figures Cross Chasse Fish Tail Forward Lock Step Four Quick Run Heel Pivot (Quarter Turn To Left) Natural Pivot Turn Natural Turn Progressive Chasse Running Finish Running Right Turn Tipple Chasse To Right V6 Zig-Zag, Back Lock And Running Finish Following Figures Progressive Chasse Reverse Pivot Heel Pivot (Quarter Turn To Left) Four Quick Run V6 (2-12, heel should lower on previous step) Six Quick Run (heel should lower on previous step) Hover Corte'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Natural SpinTurn' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Natural SpinTurn' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));

