-- Figure: Natural Turn (Quickstep)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Natural Turn',
    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
    true,
    'RF',
    'LF',
    'LF',
    'RF',
    'Closed Position',
    'Closed Position',
    '["Closed Telemark","Cross Chasse","Fish Tail","Forward Lock","Four Quick Run","Heel Pivot (Quarter Turn To Left)","Natural Pivot Turn","Natural Turn","Progressive Chasse","Running Finish","Running Right Turn","Six Quick Run","Tipple Chasse To Right","V6","Zig-Zag","Back Lock And Running Finish"]',
    '["Closed Impetus (after 1-3)","Tipple Chasse To Right (after 1-3)","Natural Turn And Back Lock","Natural Pivot Turn","Natural Spin Turn","Natural Turn With Hesitation","Natural Turn","Cross Chasse (use 6th step of Natural Turn as entry)","Forward Lock (and then Quick Open Reverse","after 1-5 of Natural Turn ending DC","; or and then any Natural figures","after 1-5 of Natural Turn ending DW of new LOD",")","Zig-Zag","Back Lock And Running Finish (use 6th step of Natural Turn as entry)","Tipsy To R (after 1-4 of Natural Turn)","Rumba Cross"]',
    'The step can be underturned to end Man facing new LOD, in which case, 1/4 turn should be completed between 4-5. The heel pull can be underturned to face new LOD. Pay special attention not to tilt shoulder. Shoulder needs to maintain flat throughout. Head follows elbow. When preceding step finishes with head turned to R, on this S, do not turn head sharp to left. Leave head and turn body underneath, smooth movement. Collect at e/o 3.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

