-- Figure: QuarterTurn to Right (Quickstep)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'QuarterTurn to Right',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'RF',
                    'Closed Position or Outside Partner Position (depending on previous figure)',
                    'Square, inline, step in between man''s legs',
                    '["Closed Telemark","Fish Tail","Four Quick Run","Progressive Chasse","Running Right Turn","V6"]',
                    '["Progressive Chasse","Reverse Pivot","Heel Pivot (Quarter Turn To Left)","Four Quick Run","V6 (2-12","L heel should still lower on preceeding step)","Six Quick Run (L heel should still lower on preceeding step)","Hover Corte"]',
                    'If this figure starts facing LOD:
Leader: turn 1/4 to R between 1-2, and 1/8 between 2-3.
Follower: turn 3/8 to R between 1-2, body turns less, finish the turn on 3.
Don''t let head and shoulder weight drop back. It''s controlled action.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

