-- Figure: Rumba Cross (Rumba)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Rumba Cross',
    (SELECT id FROM dance_type WHERE name = 'Rumba'),
    true,
    'LF',
    'RF',
    'RF',
    'LF',
    'Closed Position',
    'Backing LOD',
    '["Natural Pivot Turn","Natural Turn","Rumba Cross"]',
    '["Running Right Turn","Rumba Cross"]',
    'If preceding the Rumba Cross with 1-5 Natural Turn, a sway to L would be used on step 5 which could be held at the beginning of step 1 of the Rumba Cross. This sway assists in maintaining forward movement through the turn. The Rumba Cross may be danced twice. When preceding with a Natural Pivot Turn, S is added before this Q. Lady LF back, continue with the rotation, swing right hip up, back to R, left side is still poised forward (when pivoting), body to Man. head stretch left. Q: RF cross track in the back, activate butt muscle, hip to Man. Even though Lady is going backward, mentally, feel traveling forward (body diagonally left upward), should not be feeling taking body/shoulder back. Q: LF crosses in front of RF | Backing Wall | T | 1/4 between 1-2 | Sway(L) | Up LF almost pulls back straight, not too much room there. Lady''s head stays in place, after QQ, as body turns underneath the head, head left. S: RF fwd between partner''s feet. End with LF back | Start Facing LOD, End backing LOD | TH | 1/4 between 2-3. | Continue to turn 1/2 on 3 (Pivoting action) | Sway(S) | Up, lower e/o 3 Pivot, head may turn to R (or keep left). needs to be on the foot, ribs to Man. Do not level up shoulders and hips, leaving R side positive. R knee is forward over the toe, completely balanced on RF.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

