-- Figure: Tipple Chasse To Right (Quickstep)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Tipple Chasse To Right',
    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
    true,
    'LF',
    'RF',
    'RF',
    'LF',
    'Closed Position',
    'Closed Position',
    '["Back Lock","Cross Swivel","Hover Corte","Natural Turn","Natural Turn And Back Lock","Progressive Chasse To Right","Tipsy To L"]',
    '["Natural Turn And Back Lock","Natural Pivot Turn","Natural Spin Turn","Natural Turn With Hesitation","Natural Turn","Quick Open Reverse (at corner","when ended DC)","Fish Tail (at corner","when ended DC)","Tipsy To R (1-4 at corner","then followed by Tipsy to L)","Four Quick Run (at corner","LF back with Lady OP","TH","S into Four Quick Run)","V6 (2-12","at corner","LF back with Lady OP","TH","S into 2-12 V6)","Tipsy To L (then into 2-12 V6 DC or 2-5 Back Lock down LOD)","Six Quick Run (at corner","LF back with Lady OP","TH","S into Six Quick Run)"]',
    'The man begins shaping, bending his spine to the right. After the check step, he returns his spine to the left. The degree to which the direction of movement changes determines how much checking is done on the check step. To continue in a line down the floor, there is hardly any check at all. Silver/Gold: Underturned Tipple Chasse: when starting BLOD after 1-3 of Natural Turn, less turn can be made so this ends with man facing new LOD. Then, step 4 will be to the side, flex knees to check the turn. Continue with 2-5 Forward Lock, moving DC of new LOD. Step 5 as Lady must be taken diagonal back when this alignment is used. Rise will be: slight rise on 2 and 3, lower on 4, commence to rise e/o 4, continue to rise on 5 and 6, up on 7, lower e/o 7. footwork: step 4 will be TH, and IE of T of LF. Sway: to R with head turned to R (Lady to L) may be used. This can be used along the side of the room turning 3/8 on the Chasse to end DC. Follow with Quick Open Reverse or Fishtail.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Tipple Chasse To Right' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Tipple Chasse To Right' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));

