-- Figure: Open Impetus Turn (Waltz)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Open Impetus Turn',
    (SELECT id FROM dance_type WHERE name = 'Waltz'),
    true,
    'LF',
    'RF',
    'RF',
    'LF',
    'Closed Position',
    'Promenade Position',
    '["Curved Feather to Back Feather","Natural Turn","Natural Twist Turn","Reverse Wave"]',
    '["Feather Step","Weave from PP","Natural Weave (Natural Weave from PP)","Natural Zig-Zag from PP","Curved Feather to Back Feather (starting in PP)"]',
    'Maintain the sway from previous figure as you lower through CBM, keep the diagonal stretch. Do not lift the toe off the floor. The ball of the foot needs to stay skimming the floor. Do not turn too early, swing left side up (do not drop left shoulder, to be light on Man), stay behind Man. Allow feet to turn. Pull center back. Let head finish the action at the very last. Head turn slowly. Finish with body slightly ahead of Lady.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Open Impetus Turn' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Open Impetus Turn' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));

