-- Figure: Back Lock (Quickstep)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Back Lock',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'RF',
                    'Closed Position',
                    'Closed Position',
                    '["Progressive Chasse To Right","Tipsy To L"]',
                    '["Closed Impetus","Tipple Chasse To Right","Running Finish","Tipsy To R"]',
                    'When one is doing Back Lock, the partner is doing Forward Lock.
The Man (but not the Lady) may use foot rise at the end of 1.The Footwork would be THT, but left heel must not rise abruptly.
The Lady must release the toe of the left foot from the floor as it starts to move back to become step 3.
Body should be backing between wall and DW throughout.
Lock step has zero turn, more rotation. Rotate more to R.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Back Lock' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Back Lock' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));

