                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'ClosedTelemark',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Closed Position',
                    '["Double Reverse Spin","Heel Pivot (Quarter Turn To Left)","Reverse Pivot"]',
                    '["Running Right Turn","Natural Turn And Back Lock","Natural Pivot Turn","Natural Spin Turn","Natural Turn With Hesitation","Natural Turn","Quarter Turn to Right","Forward Lock","Fish Tail","Four Quick Run (at corner","LF back with Lady OP","TH","S","into Four Quick Run)","Six Quick Run (at corner","LF back with Lady OP","TH","S","into Six Quick Run)"]',
                    'Strong big step back, use CBM at the same time.
Do not take shoulders back, do not leave centre fwd which will block Man.
R shoulder connect down, R side is anchor for left turning figure. Feel strong upward, leftward through left side (L side slightly raised or heel turns).
When stepping RF, keep contact with Man, step shouldn''t be too close to Man. Need to leave room between Lady''s RF and Man''s LF for Man to step through his next OP step.
Shape head to right (actually by keeping the head where it is, when body turns left, head will be in the shaping right position). Then, head returns to left at next step.
Lowering at end of the step, before driving into next step.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

