-- Figure: Natural Pivot Turn (Waltz)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Natural Pivot Turn',
                    (SELECT id FROM dance_type WHERE name = 'Waltz'),
                    true,
                    'RF',
                    'LF',
                    'LF',
                    'RF',
                    'Closed Position',
                    'Closed Position',
                    '["Closed Telemark","Cross Chasse","Fish Tail","Forward Lock","Four Quick Run","Quarter Turn to Left","Natural Pivot Turn","Natural Turn","Progressive Chasse","Running Finish","Running Right Turn","Tipple Chasse To Right","V6","Zig-Zag Back Lock Running Finish"]',
                    '["Natural Turn And Back Lock","Natural Pivot Turn","Natural Spin Turn","Natural Turn With Hesitation","Natural Turn","Rumba Cross"]',
                    'Difference between a Pivot Turn and a Spin Turn is that there is no Rise in Pivot Turn. There is Rise (and brush) in Spin Turn.
At corner: turn 3/8 to face DW on new LOD.
Turn amount is up to 1/2 to face BLOD, followed by any Natural figure.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Natural Pivot Turn' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Natural Pivot Turn' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));

