-- Figure: Natural Spin Turn (Quickstep)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Natural Spin Turn',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'LF',
                    'Closed Position',
                    'Closed Position',
                    '["Closed Telemark","Cross Chasse","Fish Tail","Forward Lock Step","Quarter Turn to Left (Heel Pivot)","Natural Pivot Turn","Natural Turn","Progressive Chasse","Running Finish","Running Right Turn","Tipple Chasse to Right","V6","Zig-Zag Back Lock Running Finish"]',
                    '["Progressive Chasse","Reverse Pivot","Quarter Turn to Left (Heel Pivot)","Four Quick Run","V6","Six Quick Run","Hover Corte"]',
                    'Keep head to far left, follow L elbow, outside circle. Extend.
Have the middle of body go forward to Man and keep leg moving, but leaving head behind which creates more extension, then head catches up.
Don''t pause body movement. Simply just leave head behind.
When connecting with V6 (QQS lock step), the footwork for this count becomes THT.'
                )
