-- Figure: Quick Open Reverse (Quickstep)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Quick Open Reverse',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'RF',
                    'Closed Position',
                    'Facing LOD',
                    '["Double Reverse Spin","Forward Lock","Heel Pivot (Quarter Turn To Left)","Progressive Chasse","Reverse Pivot","Running Finish","Running Right Turn","Tipple Chasse To Right","V6","Zig-Zag","Back Lock And Running Finish"]',
                    '["Progressive Chasse","Reverse Pivot (after step 3)","Four Quick Run","Heel Pivot (Quarter Turn To Left) (after 1-3 of Quick Open Reverse)","Hover Corte"]',
                    'When this is the danced after a Forward Lock, one walk on S is added (Man RF fwd, Lady LF back)
Prepping the walk: get to knees, hip rotate to R, which gives more room to move as well.
When the Progressive Chassé is danced after an underturned Natural Spin Turn or an Impetus Turn as an entry to the Quick Open Reverse, the normal alignment of the Progressive Chassé will be (from Man''s view):
1. Backing DC against LOD
2. Pointing DC
3,4,5 Facing DC.
When the Progressive Chassé is taken after a Natural Spin turn danced with normal alignment it will be:
1 Backing DC
2 Pointing to LOD
3,4,5 Facing LOD'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Quick Open Reverse' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Quick Open Reverse' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));

