-- Figure: Running Right Turn (Quickstep)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Running Right Turn',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'LF',
                    'Closed Position',
                    'Open Position',
                    '["Closed Telemark","Fish Tail","Four Quick Run","Progressive Chasse","Rumba Cross","V6"]',
                    '["Fish Tail (normal; or when ended DC)","Natural Turn And Back Lock","Natural Pivot Turn","Natural Spin Turn","Natural Turn With Hesitation","Natural Turn","Quarter Turn to Right","Forward Lock","Quick Open Reverse (when ended DC)","Tipsy To L (Tipsy to L into 2-12 V6 DC or 2-5 Back Lock down LOD)"]',
                    'Other alignments:
Across corner: 3/8 on Pivot, 1/2 on Natural Turn, 3/8 on Running Finish.
Two corners: 3/8 on Pivot, 3/8 on Natural Turn, 1/4 on Running Finish
Side of room: 1/2 on pivot, 1/2 on Natural Turn, 3/8 on Running Finish
When 3/8 is made on Running Finish, using "pointing" instead of "facing" at step 9 for Man.
Alternative timing SQQ may be used on steps 5-7, in which case, SQQS will be used on the Running Finish.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

