-- Figure: HoverFeather (Foxtrot)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'HoverFeather',
    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
    true,
    'LF',
    'LF',
    'RF',
    'RF',
    'Closed Position',
    'Closed Position',
    '["Hover Telemark","Natural Turn","Reverse Wave"]',
    '["Three Step","Reverse Turn (just Reverse Turn with Feather finish","or 1-4 Reverse Turn check and Basic Weave)","Change Of Direction","Closed Telemark","Open Telemark and Feather Ending","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Hover Telemark","Reverse Wave","Top Spin (check back after step 3 of feather finish)","Outside Swivel (check back after step 3 of Feather Step)","Fallaway Reverse and Slip Pivot","Bounce Fallaway with Weave Ending"]',
    'Body will overturn slightly to R on preceding Heel Pull. the footwork of the Heel Pull will be: 1. TH; 2 H; IE of foot, whole foot, then T of RF and pressure on IE of T of LF. Rise e/o preceding Heel Pull. Up. Compress right side, change angle through diagonal, allow head to prepare to go outside partner. Note -- Body will overturn to R on preceding Brush step. The Lady will rise from the ball of LF at the end of the Brush step. The L heel does not touch the floor. Keep counter balance in the Man''s arms, leave arms to Man, as you swing rightwards. Pull center back. Feel the left hip is dancing across inside edge of left foot. Keep head very left, feel like dancing rib cage across the feet. Hold diagonal extra shaping for the 2 steps. Push off standing leg to move. Do not take upper body back too fast. Take everything through lower center. Lower center move faster than upper center. Keep counter balance in the Man''s arms, leave arms to Man, as you swing rightwards. Pull center back.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'HoverFeather' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'HoverFeather' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));

