-- Figure: HoverTelemark (Foxtrot)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'HoverTelemark',
                    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Promenade Position',
                    '["Basic Weave","Bounce Fallaway with Weave Ending","Closed Impetus and Feather Finish","Fallaway Reverse and Slip Pivot","Feather Step","Hover Feather","Natural Hover Telemark","Natural Telemark","Natural Twist Turn","Natural Weave","Natural Zig-Zag from PP","Open Telemark and Feather Ending","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Reverse Turn","Top Spin","Weave from PP"]',
                    '["Feather Step","Basic Weave","Hover Feather","Natural Turn","Natural Weave","Natural Telemark","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Natural Twist Turn","Natural Zig-Zag from PP","Natural Hover Telemark","Curved Feather to Back Feather"]',
                    'Hover Telemark can finish in Promenade Position. See Hover Telemark to PP.
Note unusual type of rise.
When landing on LF, small range of motion to recover from sway.
When traveling backwards, never turn shoulders so you don''t cross center line. When going back, upper body is not a rotary motion, body should be stretching diagonal.
Left side is very lengthened, stretched. Head shaped to right. Keep elbows in front of body. Pick up stomach back to spine.
Then dissolve the sway.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'HoverTelemark' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'HoverTelemark' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));

