-- Figure: Open Telemark, Natural Turn to Outside Swivel and Feather Ending (Foxtrot)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Open Telemark, Natural Turn to Outside Swivel and Feather Ending',
    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
    true,
    'LF',
    'RF',
    'RF',
    'RF',
    'Closed Position',
    'Closed Position',
    '["Closed Impetus and Feather Finish","Feather Step","Hover Cross","Hover Feather","Hover Telemark","Natural Hover Telemark","Natural Telemark","Natural Twist Turn","Natural Zig-Zag from PP","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Top Spin"]',
    '["Reverse Turn","Closed Telemark","Open Telemark and Feather Ending","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Three Step (at corner)","Change Of Direction (at corner)","Hover Telemark (at corner)","Reverse Wave (at corner)","Weave from PP (after step 7)","Bounce Fallaway with Weave Ending","Natural Zig-Zag from PP (after step 7)"]',
    'When the Outside Swivel is danced at the side of the room to be followed by Feather Ending into Top Spin, 1/8 turn to R is made on step 7 and 8-10 will be taken DC against LOD. Weave from PP may also be danced following this underturned Outside Swivel, Man using the Basic Weave alignment. If dancing this underturned Outside Swivel at a corner steps 8-11 will be taken DC of new LOD. Follow as for Feather. The Outside Swivel (steps 7-8) could be danced by checking OP on any Feather Movement taken DW without turn and followed as in the previous paragraph.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

