-- Figure: ReverseWave (Foxtrot)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'ReverseWave',
                    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'RF',
                    'Closed Position',
                    'Fan Position',
                    '["Basic Weave","Bounce Fallaway with Weave Ending","Closed Impetus and Feather Finish","Fallaway Reverse and Slip Pivot","Feather Step","Hover Cross","Hover Feather","Natural Hover Telemark","Natural Telemark","Natural Twist Turn","Natural Weave","Natural Zig-Zag from PP","Open Telemark and Feather Ending","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Reverse Turn","Top Spin","Weave from PP"]',
                    '["Feather Step","Basic Weave (after step 4)","Closed Impetus and Feather Finish (after step 6)","Open Impetus (after step 6)","Hover Feather (after step 8)","Curved Feather to Back Feather (at corner)"]',
                    'There are five alignments of the Reverse Wave
Facing LOD 3/8 between 1-3, 1/8 between 4-6, 3/8 between 7-8 (or less at corner)
Facing LOD 3/8 between 1-3, 1/4 between 4-6 to back DW of new LOD, 1/4 between 7-8
Facing DW 1/2 between 1-3, then continue as in alignment (1)
Facing DW 1/2 between 1-3, then continue as in alignment (2)
Facing DC 3/8 between 1-3, 1/4 between 4-6 to back the new LOD, 3/8 between 7-8.
Alignments 2,4, and 5 are used to turn a corner.
Extend the Reverse Wave with SQQ after step 6:
Man: continue BLOD
S: TH, LF back,
Q: T, RF back, R shoulder leading
Q: TH, LF back in CBMP
Lady: continue facing LOD. Poise is not back weight, but shoulder is dancing in the back of the feet, do not fall forward.
S: HT, RF fwd, then relax R shoulder down, allow left thigh and knee to dance forward, ahead of body. Drive out of R hip. Swing L hip up and forward for next step
Q: T, LF fwd, L shoulder leading, prepare to step OP.
Q: TH, RF fwd, CBMP, OP. Pull RF underneath the body. Body is shaping back, which is because center of body is going forward, not bending backward.
Head: can keep head left, or shape to R. The feeling is legs are dancing ahead of body.
Preceding Figures: Basic Weave, Bounce Fallaway with Weave Ending, Closed Impetus and Feather Finish, Fallaway Reverse and Slip Pivot, Feather Step, Hover Cross, Hover Feather, Natural Hover Telemark, Natural Telemark, Natural Twist Turn, Natural Weave, Natural Zig-Zag from PP, Open Telemark and Feather Ending, Open Telemark, Natural Turn, Outside Swivel and Feather Ending, Reverse Turn, Top Spin, Weave from PP
Following Figures: Feather Step, Basic Weave (after step 4), Closed Impetus and Feather Finish (after step 6), Open Impetus (after step 6), Hover Feather (after step 8), Curved Feather to Back Feather (at corner)'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

