    (SELECT id FROM dance_type WHERE name = 'Tango'),
    true,
    'LF',
    'LF',
    'RF',
    'LF',
    'Closed Position',
    'Closed Position',
    '["Basic Reverse Turn","Chase","Contra Check","Fallaway Four Step","Fallaway Promenade","Five Step","Four Step","Natural Promenade Turn","Natural Twist Turn","Open Finish","Open Promenade","Open Reverse Turn","Lady In Line","Open Reverse Turn","Lady Outside","Oversway","Progressive Link","Progressive Side Step Reverse Turn"]',
    '["Walk (LF)","Progressive Side Step","Progressive Link","Back Corte","LF Rock","Open Reverse Turn","Lady Outside","Open Reverse Turn","Lady In Line","Progressive Side Step Reverse Turn","Reverse Outside Swivel","Basic Reverse Turn","Fallaway Reverse and Slip Pivot","Four Step","Outside Swivel","Four Step Change","Brush Tap","Fallaway Four Step","Oversway","Five Step","Contra Check"]',
    'Man may turn square to the lady in step 3, to end backing DC. Footwork for man would then be IE BH and for the lady IE of foot.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
