-- Figure: Natural Promenade Turn (Tango)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Natural Promenade Turn',
    (SELECT id FROM dance_type WHERE name = 'Tango'),
    true,
    'LF',
    'LF',
    'RF',
    'LF',
    'Closed Position',
    'Closed Position',
    '["Basic Reverse Turn","Chase","Contra Check","Fallaway Four Step","Fallaway Promenade","Five Step","Four Step"]',
    '["Closed Promenade","Open Promenade","Promenade Link","Back Open Promenade","Fallaway Promenade","Rock Turn (2-7)"]',
    'Amount of Turn: 3/4 to right. If danced along the side of the room, 3/4 still made; following promenade may be taken to the center or a slight body turn to R may be used. When followed by Rock Turn, 4th step omitted and commence DC; better to turn 1/2 to R between 1-3 of Rock Turn and end facing DW. Track man''s hips, stay behind; depending on finishing travel direction, lady may need to swivel on LF (S) quite a bit. When followed by steps 2-7 Rock Turn, skip step 4 (placing RF to side), it is more flat and rotational. Natural Promenade Turn follows the Fallaway Promenade. Alignment details: Leader: DW pointing to W; Q: To Wall; Q: BDW; S: Down LOD end facing LOD. Follower: S: DW pointing LOD; Q: Pointing DW; Q: DW; S: BLOD to end facing Center.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

