-- Figure: Natural Twist Turn (Tango)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Natural Twist Turn',
                    (SELECT id FROM dance_type WHERE name = 'Tango'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'LF',
                    'Closed Position',
                    'Promenade Position',
                    '["Fallaway Promenade","Progressive Link"]',
                    '["Closed Promenade","Open Promenade","Natural Promenade Turn","Promenade Link","Back Open Promenade","Fallaway Promenade","Back Corte","LF Rock"]',
                    'Amount of Turn: A complete turn to the right
Other variations:
7/8 to R could be made to end facing LOD. The following Promenade would move DC.
3/4 to R could be made at a corner or at the side of the room to end facing DC. The following Promenade would move to center.
When following with Back Corté or LF Rock Man will turn a further 1/4 to face partner

Follower notes:
Amount of Turn: a complete turn to R.
2 styles (below) to finish this figure, either is ok, but they all finish in the same alignment. (Tendency is LF is not swiveled enough.)
5-step style finish: (traditional way), Lady pivot on LF on step 6.
Pivoting on LF, it needs to pivot enough to have LF finish in the correct position (tendency is underturn).
LF begins swivel when it starts to receive weight, not delay till full weight on it and then swivel. The weight is in transition. When swivel finishes, full weight is transferred onto LF.
4-step style finish, Lady pivot on RF on step 5.
Pivoting on RF on step 5, then place LF parallel to RF in the Promenade Position.
Preceding Figures
Fallaway Promenade
Progressive Link
Following Figures
Closed Promenade
Open Promenade
Natural Promenade Turn
Promenade Link
Back Open Promenade
Fallaway Promenade
Back Corte
LF Rock'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

