-- Figure: Open Promenade (Tango)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Open Promenade',
    (SELECT id FROM dance_type WHERE name = 'Tango'),
    true,
    'LF',
    'LF',
    'RF',
    'LF',
    'Promenade Position',
    'Open Finish',
    '["Basic Reverse Turn","Chase","Contra Check","Fallaway Four Step","Fallaway Promenade","Five Step","Four Step","Natural Promenade Turn","Natural Twist Turn","Open Finish","Open Promenade","Open Reverse Turn","Lady In Line","Open Reverse Turn","Lady Outside","Oversway","Progressive Link","Progressive Side Step Reverse Turn","Reverse Outside Swivel","Basic Reverse Turn","Fallaway Reverse and Slip Pivot","Four Step","Four Step Change","Brush Tap","Fallaway Four Step","Oversway","Five Step","Back Corte","LF Rock","Outside Swivel","Closed Promenade","Open Promenade","Natural Promenade Turn","Promenade Link","Back Open Promenade","Fallaway Promenade"]',
    '["Walk (LF)","Progressive Side Step","Progressive Link","Open Reverse Turn","Lady Outside","Open Reverse Turn","Lady In Line","Progressive Side Step Reverse Turn","Reverse Outside Swivel","Basic Reverse Turn","Fallaway Reverse and Slip Pivot","Four Step","Four Step Change","Brush Tap","Fallaway Four Step","Oversway","Five Step","Back Corte","LF Rock","Outside Swivel","Closed Promenade","Open Promenade","Natural Promenade Turn","Promenade Link","Back Open Promenade","Fallaway Promenade"]',
    'Open Finish (as opposed the Closed Finish in Closed Promenade.) This is not "back and across", LF is fairly straight on the line with RF. Allow shoulder and arm and upper body to rotate to right. Left shoulder is quite forward, body is twisted. Keep hip up/fwd toward Man (do not sit). Extend back, head left and extend. Stay very left of Man. Do not lower L heel too quickly till you see the center is still moving toward same direction (ie. it will be backward step); it could be a swivel, then you change moving direction. Note: Man may turn square to the lady in step 3, to end backing DC. Footwork for man would then be IE BH and for the lady IE of foot. Head should keep the same distance with Man''s head at all times. Keep the volume between 2 heads. There is the tendency that Lady''s head goes too far forward on this ''Q'' and getting weight on to her RF (this shorten the distance with Man, cut in his space), then the head comes back to left - which is too late.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

