-- Figure: Progressive Link (Tango)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Progressive Link',
    (SELECT id FROM dance_type WHERE name = 'Tango'),
    true,
    'LF',
    'LF',
    'RF',
    'LF',
    'Closed Position',
    'Promenade Position',
    '["Back Corte","Basic Reverse Turn","Brush Tap","Chase","Closed Finish","Closed Promenade","Fallaway Reverse and Slip Pivot","Four Step Change","Open Finish","Open Promenade","Open Reverse Turn","Lady In Line","Open Reverse Turn","Lady Outside","Outside Swivel","Progressive Side Step Reverse Turn","Promenade Link","Reverse Outside Swivel","Rock Turn","Walk"]',
    '["Closed Promenade","Open Promenade","Natural Twist Turn","Natural Promenade Turn","Promenade Link","Back Open Promenade","Fallaway Promenade","Chase"]',
    'The figure has solid, sharp feeling, not soft. It is more of an "upward" action with body projecting upward. 90 body rotation in body seems to give the right look and impact.\n\nPromenade position:\nLady''s L hip feels like rolled downward and backward, R hip fwd stretched, toward Man.\nHip is level, Lady may feel R hip is higher.\nHips has an diagonal angle to Man. L hip is \"released\". Upper body is closed more.\nActions are in hips, nothing should affect top shoulder line, arm relaxed, with tone, not noodly and don''t change elbow during the step.\nR hand: do not bend wrist back. wrist forward.\nL hand: maintain \"up and out\" position, do not slide.\nHead turning: should not be on its own, shouldn''t be too late or too early. Turning the head when weight is changing onto LF.\nHead change finishes when the action finishes.\n\nThe figure starts in DW. But often, link is preceded by 2 walks which started DW. Walks naturally curve to left, so the Link will end up with Man''s feet facing LOD, Woman''s feet facing center., traveling DC.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Progressive Link' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Tango'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Progressive Link' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Tango'));

