-- Figure: Rock Turn (Tango)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Rock Turn',
    (SELECT id FROM dance_type WHERE name = 'Tango'),
    true,
    'LF',
    'LF',
    'RF',
    'RF',
    'Closed Position',
    'Closed Position',
    '["Natural Promenade Turn","Progressive Side Step","Walk"]',
    '["Walk (LF)","Progressive Side Step","Progressive Link","Back Corte","LF Rock","Open Reverse Turn","Lady Outside (when preceding figure ended DC)","Open Reverse Turn","Lady In Line (when preceding figure ended DC)","Progressive Side Step Reverse Turn (when preceding figure ended DC)","Reverse Outside Swivel (when preceding figure ended DC)","Basic Reverse Turn (when preceding figure ended DC)","Fallaway Reverse and Slip Pivot (when preceding figure ended DC; or normal)","Four Step","Outside Swivel","Four Step Change","Brush Tap","Fallaway Four Step","Oversway","Five Step","Contra Check"]',
    'Start with a preparatory step S on LF (leader) and RF (follower). The figure involves a sequence of S and Q timings with forward, side, back steps, weight transfers, and turns. Detailed alignment and amount of turn instructions are provided for each step. Lady may choose head position and direction, and must maintain space and posture. Specific body leads and foot placements include CBMP, DW, BC, etc. The figure ends with a closing movement of RF to LF slightly back (leader) and LF closing to RF slightly forward (follower).'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

