-- Figure: Contra Check (Waltz)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Contra Check',
                    (SELECT id FROM dance_type WHERE name = 'Waltz'),
                    true,
                    'LF',
                    'LF',
                    'RF',
                    'RF',
                    'Closed Position',
                    'Promenade Position',
                    '["Double Reverse Spin","Fallaway Reverse and Slip Pivot","Hesitation Change","Reverse Pivot","Reverse Turn"]',
                    '["Chasse From Promenade Position","Weave From Promenade Position","Cross Hesitation","Wing","Left Whisk"]',
                    'Focus: smoothness, rotation, elasticity, lightness, softness, finish the extension.
Preparations and extension details include: bend/lower left knee, shoulder level off, rotate hips to left; do not send stomach muscle forward; connect center into hip joint; CMBP; RF point back first, toe turned in; keep right heel up; weight split; body rotate left while keeping left side up to Man; keep left toe down; flex both knees; get there first, then give (R) hip and ribs to Man; extend R arm; lift glute and center up; imagine stretching R side; upper body rotation and sway; continuous extension to head; elasticity, smoothness, lightness; do not sit or just go down; bounce up; arms belong to partner, never pull back; extend arm to give space; frame: breathe, feel free, continuous movement; push off back foot into PP; stay very left; start articulating head turn; turn may be made between 2-3 to end in PP moving DC; articulate head; prep for next step: lower first and step big.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

