-- Figure: Open Telemark and Wing (Waltz)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Open Telemark and Wing',
    (SELECT id FROM dance_type WHERE name = 'Waltz'),
    true,
    'LF',
    'RF',
    'RF',
    'LF',
    'Closed Position',
    'Closed Position',
    '["Back Whisk","Basic Weave","Contra Check","Fallaway Whisk","Open Impetus","Open Telemark","Outside Change","Turning Lock","Turning Lock to R","Weave From Promenade Position","Whisk"]',
    '["Closed Telemark (taking step 1 in CBMP OP on L side)","Open Telemark (taking step 1 in CBMP OP on L side)","Double Reverse Spin (taking step 1 in CBMP OP on L side)","Progressive Chasse To R (taking step 1 in CBMP OP on L side)","Reverse Turn (taking step 1 in CBMP OP on L side)","Drag Hesitation","Fallaway Reverse And Slip Pivot","Whisk (at corner)"]',
    'Wing can be used from other positions. Less turn can be made on Wing to end facing LOD.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Open Telemark and Wing' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Open Telemark and Wing' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));

