-- Figure: Reverse Corte (Waltz)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Reverse Corte',
    (SELECT id FROM dance_type WHERE name = 'Waltz'),
    true,
    'RF',
    'RF',
    'LF',
    'RF',
    'Closed Position',
    'Closed Position',
    '["Closed Impetus","Natural Spin Turn","Outside Spin","Reverse Turn"]',
    '["Natural Turn (4-6; or 4-6 when ending BDW)","Fallaway Whisk","Back Whisk (normal; or Back whisk with turn at corner)","Closed Impetus (when ending BDW)","Back Lock (when ending BDW)","Outside Change (at corner; or into Closed Wing)","Open Impetus (when ending BDW)","Outside Spin (underturned)"]',
    'On step 2 turn may be made on ball of RF with foot flat. Footwork would then be 1. THT; 2 Toes both feet; 3 TH(RF). Note: Other alignments (between steps 1-2) are the following, with different ending alignment: backing LOD, 1/2 L between 1-2, ending against LOD; backing LOD, 5/8 L between 1-2, ending BDW against LOD; backing DC, 1/4 to L between 1-2, ending BDC against LOD. Follower: When Man uses different alignments as above, the Lady will turn: Just over 1/4 to L between 1-2, just under 1/4 to L between 2-3; 3/8 to L between 1-2, 1/4 to L between 2-3; 1/8 to L between 1-2, 1/8 to L between 2-3.'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
    ending_foot_leader = EXCLUDED.ending_foot_leader,
    starting_foot_follower = EXCLUDED.starting_foot_follower,
    ending_foot_follower = EXCLUDED.ending_foot_follower,
    starting_position = EXCLUDED.starting_position,
    ending_position = EXCLUDED.ending_position,
    preceding_figure_names = EXCLUDED.preceding_figure_names,
    following_figure_names = EXCLUDED.following_figure_names,
    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Reverse Corte' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Reverse Corte' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));

