-- Figure: Reverse Pivot (Waltz)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Reverse Pivot',
                    (SELECT id FROM dance_type WHERE name = 'Waltz'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'LF',
                    'Backing LOD',
                    'Facing DW',
                    '["Closed Impetus","Natural Spin Turn","Outside Spin","Reverse Turn"]',
                    '["Closed Change LF (when ending DW)","Whisk (when ending DW)","Double Reverse Spin (when ending DW; or when ending LOD; or when ending DC)","Contra Check (when ending DW)","Reverse Turn (1-3 into Basic Weave when ending LOD; or when ending DC)","Progressive Chasse To R (3/8 turn","when ending LOD; or when ending DC)","Closed Telemark (when ending DC)","Open Telemark (when ending DC)","Fallaway Reverse And Slip Pivot (when ending DC)"]',
                    'If the Reverse Pivot is started backing DC the alignment for the Pivot (Man) would be "to center, toe turned in".
Note also that this step is in CBMP owing to the body turning strongly to L as the RF foot slips back.
This step is on the half beat, at end of last step of previous figure (e.g. Closed Impetus) - body has not completely lowered in previous figure when stepping on this step.
Allow this step to blend smoothly with the preceding step, if necessary borrowing from the next beat.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Reverse Pivot' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Reverse Pivot' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Waltz'));

