-- Figure: Cross Chasse (Quickstep)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Cross Chasse',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'LF',
                    'Open Position',
                    'Outside Partner Position',
                    '["Change of Direction","Double Reverse Spin","Heel Pivot (Quarter Turn To Left)","Natural Turn","Reverse Pivot","Natural Turn And Back Lock","Natural Pivot Turn","Natural Spin Turn","Natural Turn With Hesitation","Natural Turn","Forward Lock","Fish Tail"]',
                    '["Natural Turn And Back Lock","Natural Pivot Turn","Natural Spin Turn","Natural Turn With Hesitation","Natural Turn","Forward Lock","Fish Tail"]',
                    'Styling option: turn head to R

Running Cross Chasse
In stead of closing feet above, keep moving (''running") forward:
Leader
S: RF fwd, CBMP, OP | FDW | HT
S: LF fwd | FDW | T | -- | Sway(S) | CBM | Rise e/o 1
Q: RF diagonally fwd | FDW | T | -- | Sway(L) | up
Q: LF fwd, L shoulder leading | FDW | TH | -- | Sway(L) | up, lower e/o 3
S: RF fwd in CBMP, OP | FDW | H | -- | Sway(S) | CBM | --
Follower
S: LF back, CBMP | BDW | TH
Pay attention not to do a lot rotation through shoulders.
S: RF back | BDW | T | -- | Sway(S) | CBM | Rise e/o 1, NFR
R shoulder connects down.
Q: LF diagonally back | BDW | T | -- | Sway(R) | up
Do not rotate L shoulder.
Stretch L side.
Q: RF back, R shoulder leading | BDW | TH | -- | Sway(R) | up, lower e/o 3
S: LF back in CBMP | BDW | T | -- | Sway(S) | CBM | --'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

