-- Figure: Hover Corte (Quickstep)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Hover Corte',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'RF',
                    'Closed Position',
                    'Closed Position',
                    '["Chasse Reverse Turn","Closed Impetus","Natural Spin Turn","Quarter Turn to Right (Heel Pivot)","Quick Open Reverse"]',
                    '["Tipple Chasse to Right","Tipsy to R","Running Finish","Tipsy to L","Four Quick Run","V6","Six Quick Run"]',
                    'Be aware of Man''s center. Drive toward the Man, but not shaping too early. This figure has delayed reaction to Man''s body. Man takes head to the foot and then develops the shape out of standing leg.
Connection is lower (hips, upper legs is pressing with Man), allowing even more extension.
Think of the shape coming from lower part of abdominal first, then taking the curve up to upper body.
Don''t just bend back from waist and fall back.
The side connects to arm. When giving right ribs/side, the tone extends to R arm and give that toned arm/hand to Man forward.
At beginning: head can still kept left throughout the figure. When more comfortable, head can be more free, open to the right at end of 1st S, then close and turn to L when developing shaping.
After lowering at e/o step 3, hips turn R, makes space to move legs in between. Typically, you breathe out when coming down.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Hover Corte' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Hover Corte' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Quickstep'));

