-- Figure: Natural Turn with Hesitation (Quickstep)
INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
VALUES (
    gen_random_uuid(),
    'Natural Turn with Hesitation',
    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
    true,
    'RF',
    'RF',
    'LF',
    'LF',
    'Closed Position',
    'Open Position',
    '["Closed Telemark","Cross Chasse","Fish Tail","Forward Lock Step","Four Quick Run","Heel Pivot","Natural Pivot Turn","Natural Turn","Progressive Chasse","Running Finish","Running Right Turn","Tipple Chasse To Right","V6","Zig-Zag","Back Lock And Running Finish"]',
    '["Chasse Reverse Turn","Progressive Chasse To Right","Double Reverse Spin"]',
    'Sway in step 5-6 is optional.'
)
