                    'Tipsy to Right',
                    (SELECT id FROM dance_type WHERE name = 'Quickstep'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'LF',
                    'Closed Position',
                    'Closed Position',
                    '["Back Lock","Cross Swivel","Double Reverse Spin","Hover Corte","Natural Turn","Natural Turn And Back Lock","Progressive Chasse To Right","Reverse Pivot","Tipple Chasse To Right","Tipsy To L"]',
                    '["Forward Lock (steps 2-5)","Tipsy To L","Tipsy to Left"]',
                    'When a Tipsy is danced after a forward step on the LF any turn made will be to L. When it is danced after a step back on LF, any turn made will be to R.
Precede with a step forward on RF, OP in CBMP'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
