INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    '6694b92d-7b7a-3247-a0ff-d905209e0046',
    '7511bbf1-3e38-3761-b9df-58fc46380c7c',
    'Curve, the rotation is mostly in the hip area, follow Man''s hip, don''t stop turning to R (other you''ll block Man), continue the rotation and give Man middle and side and stay connected. Upper body/shoulder should not turn too much which will pull off from partner (but it does turn to R, otherwise Man can''t pass). Upper body is diagonally stretched (R side is upward), keep parallel to partner. Push off standing leg to move. Forward with body and arms.',
    1
);
