INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    'be3253c6-85a2-350f-875e-ccda59e2f966',
    '6431a77d-2bbf-313c-81f8-1a2d158a53ed',
    'Rotate hip more and lower more into L knee, push off LF/L leg to drive for bigger movement. Do not go downward in this step. The lowering happens in previous step (weight into heel on previous Q). This step drives forward and up (rise e/o this step). Left side now swings forward (body does not stop - which will make it look like going backward), do not swing too much up, focus on forward, body rotate a lot to the right. Head turns and shapes to R. Do not cross into Man''s space. Smooth changes. Movement should feel "free", not constrained. Body breathes.',
    1
);
