    'T',
    '-',
    '-'
);
INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    'a957cf2e-4f4c-325f-93ef-e12dde24dafc',
    '3a1bf393-d48b-3387-8be3-77c822d5e7be',
    'If Man shapes, Lady turn her head to R, but stay very left, keep ribs/side to Man. Really needs to turn body (rotate to R)',
    1
);
