INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    '09d79efa-5b3d-3b8a-a120-97fe353ec5fc',
    '010a8b4f-de2b-325f-9865-c210863ca99b',
    'Do not dip shoulder low, keep shoulders flat, swing forward, traveling. Give center to Man, shape. When swing on Q: do not dip shoulder low, keep should flat, swing forward, traveling. Give center to Man, shape. (But note: If Man shapes, Lady turn her head to R on QQ, keep ribs/side to Man.)',
    1
);
INSERT INTO dance_figure_step (id, dance_figure_id, step_number, timing, role, foot, action, footwork, alignment, amount_of_turn)
VALUES (
    'aa07ff1c-702f-3187-8ed4-44167c4118db',
    (SELECT id FROM dance_figure WHERE name = 'Curved Feather to Back Feather' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot')),
    14,
    'S',
    'FOLLOWER',
    'LF',
    'LF fwd | Facing LOD | H | - | S | CBM | -',
    '-',
