INSERT INTO dance_figure_step_comment (id, dance_figure_step_id, comment_text, display_order)
VALUES (
    'c8270704-f568-3297-ac42-94a66ee3769e',
    'aa07ff1c-702f-3187-8ed4-44167c4118db',
    'Typically, continue with Feather Finish SQQ. This first LF fwd on S, do not follow Man''s curve, step straight forward in between Man''s legs, otherwise, at the end of Feather finish, Lady''s hip will gap/end up to the side of Man''s hip. When swing on Q: do not dip shoulder low, keep should flat, swing forward, traveling. Give center to Man, shape. Breathe, release so body does not stiff up. If Man shapes, Lady turn her head to R on QQ, keep ribs/side to Man.',
    1
);

-- Figure: Fallaway Reverse and Slip Pivot (Foxtrot)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Fallaway Reverse and Slip Pivot',
                    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
                    true,
                    'LF',
                    'RF',
                    'RF',
                    'RF',
                    'Closed Position',
                    'Closed Position',
                    '["Basic Weave","Bounce Fallaway with Weave Ending","Closed Impetus and Feather Finish","Fallaway Reverse and Slip Pivot","Feather Step","Hover Cross","Hover Feather","Natural Hover Telemark","Natural Telemark","Natural Twist Turn","Natural Weave","Natural Zig-Zag from PP","Open Telemark and Feather Ending","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Reverse Turn","Top Spin","Weave from PP"]',
                    '["Change Of Direction","Hover Telemark","Reverse Wave","Fallaway Reverse and Slip Pivot","Basic Weave (At corner)","Open Telemark and Feather Ending (At corner)"]',
                    'Different timings that can be used on this figure: SQQS, SQQ&, SQ&Q, S&QQ, QQQQ. (S: 2 beats, Q: 1 beat, &: 1/2 beat)
When this figure is danced into corner, start DW or LOD to follow with a Reverse figure, DC of new LOD.
Depending on the previous alignment and choreography, e.g. if starting DW into corner, the 2nd step could be taken diagonal (instead of moving along LOD)'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

