-- Figure: Hover Cross (Foxtrot)
                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Hover Cross',
                    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'RF',
                    'Closed Position',
                    'Closed Position',
                    '["Closed Telemark","Three Step"]',
                    '["Reverse Turn","Closed Telemark","Open Telemark and Feather Ending","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Fallaway Reverse and Slip Pivot","Reverse Wave","Bounce Fallaway with Weave Ending"]',
                    'Note -- A slight lowering may be used on step 4, but the L heel should not touch the floor. Do not allow body to overturn on 4.
Lady keeps her head to left (when first learning this figure), stretch left side. Alternatively, Lady can shape head to right. Slightly lift left side.
Shaping head to R goes with the sway, end of previous step 3. Make head movement really smooth, do not get to shaping right too fast
It''s all lower body. Do not turn shoulder, do not pull shoulder away from Man.
Lady slides from Man''s R side to his L side. It''s L side to L side connection with partner.
Keep head to right on steps 4-5, extend upper body even more on step 4, then return to normal starting end of step 5 (Q), then step 6 (Q).
Keep own internal balance. Flat.
Do not lock the knees, keep knees soft, compressed.
Multiple Q''s, keep flat, don''t rise
Isolate body, turn purely in feet underneath body. Allow arms to stay as still as possible.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
                    starting_foot_follower = EXCLUDED.starting_foot_follower,
                    ending_foot_follower = EXCLUDED.ending_foot_follower,
                    starting_position = EXCLUDED.starting_position,
                    ending_position = EXCLUDED.ending_position,
                    preceding_figure_names = EXCLUDED.preceding_figure_names,
                    following_figure_names = EXCLUDED.following_figure_names,
                    notes = EXCLUDED.notes;

DELETE FROM dance_figure_link WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Hover Cross' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));
DELETE FROM dance_figure_step WHERE dance_figure_id = (SELECT id FROM dance_figure WHERE name = 'Hover Cross' AND dance_type_id = (SELECT id FROM dance_type WHERE name = 'Foxtrot'));

