    'Closed Position',
    'Promenade Position',
    '["Basic Weave","Bounce Fallaway with Weave Ending","Closed Impetus and Feather Finish","Fallaway Reverse Slip Pivot","Feather Step","Hover Feather","Natural Hover Telemark","Natural Telemark","Natural Twist Turn","Natural Weave","Natural Zig-Zag from PP","Open Telemark and Feather Ending","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Reverse Turn","Top Spin","Weave from PP"]',
    '["Feather Step","Basic Weave","Hover Feather","Natural Turn","Natural Weave","Natural Telemark","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Natural Twist Turn","Natural Zig-Zag from PP","Natural Hover Telemark","Curved Feather to Back Feather"]',
    'Hover Telemark can finish in Promenade Position. Note unusual type of rise'
)
ON CONFLICT (dance_type_id, name) DO UPDATE SET
    predefined = EXCLUDED.predefined,
    starting_foot_leader = EXCLUDED.starting_foot_leader,
