                INSERT INTO dance_figure (id, name, dance_type_id, predefined, starting_foot_leader, ending_foot_leader, starting_foot_follower, ending_foot_follower, starting_position, ending_position, preceding_figure_names, following_figure_names, notes)
                VALUES (
                    gen_random_uuid(),
                    'Natural Telemark',
                    (SELECT id FROM dance_type WHERE name = 'Foxtrot'),
                    true,
                    'RF',
                    'RF',
                    'LF',
                    'RF',
                    'Closed Position',
                    'Closed Position',
                    '["Closed Telemark","Hover Telemark","Three Step"]',
                    '["Reverse Turn","Closed Telemark","Open Telemark and Feather Ending","Open Telemark","Natural Turn","Outside Swivel and Feather Ending","Three Step (at corner)","Change Of Direction (at corner)","Hover Telemark (at corner)","Reverse Wave (at corner)","Fallaway Reverse and Slip Pivot","Bounce Fallaway with Weave Ending"]',
                    'Note -- 1/2 or 5/8 turn may be used at a corner. Amount of turn in each case will be 1/4 between 1/2, whether started facing LOD or DW
Note -- When underturned, the Lady will always turn 3/8 between 1-2
This step stays on T, there is no toe release for LF into next step.
Compress into knee without lowering into heel.
Continue turning through the feet.
Take head and weight to LF, compress L knee, then brush RF.
There is RF toe release when LF is stepping back on this step.'
                )
                ON CONFLICT (dance_type_id, name) DO UPDATE SET
                    predefined = EXCLUDED.predefined,
                    starting_foot_leader = EXCLUDED.starting_foot_leader,
                    ending_foot_leader = EXCLUDED.ending_foot_leader,
